           for (const include_cleaner::Header &H : Providers) {
             if (H.kind() == include_cleaner::Header::Physical &&
                 H.physical() == MainFile)
               Satisfied = true;

             for (const include_cleaner::Include *I :
                  RecordedPreprocessor.Includes.match(H)) {
               Used.insert(I);
