}

bool SuspiciousCallArgumentCheck::areNamesSimilar(StringRef Arg, StringRef Param, Heuristic H, BoundKind BK) const {
  int8_t Threshold = -1;
  if (std::optional<int8_t> GotBound = getBound(H, BK))
    Threshold = *GotBound;

  switch (H) {
    case Heuristic::Equality: return applyEqualityHeuristic(Arg, Param);
    case Heuristic::Abbreviation: return applyAbbreviationHeuristic(AbbreviationDictionary, Arg, Param);
    case Heuristic::Prefix: return applyPrefixHeuristic(Arg, Param, Threshold);
    case Heuristic::Suffix: return applySuffixHeuristic(Arg, Param, Threshold);
    case Heuristic::Substring: return applySubstringHeuristic(Arg, Param, Threshold);
    case Heuristic::Levenshtein: return applyLevenshteinHeuristic(Arg, Param, Threshold);
    case Heuristic::JaroWinkler: return applyJaroWinklerHeuristic(Arg, Param, Threshold);
    case Heuristic::Dice: return applyDiceHeuristic(Arg, Param, Threshold);
  }
  llvm_unreachable("Unhandled heuristic kind");
}

