if (!Scale)
  return;

if (Call == Binop->getLHS()->IgnoreParenImpCasts()) {
  Hint = FixItHint::CreateReplacement(
      Binop->getSourceRange(),
      (llvm::Twine(TimeFactory) + "(" +
       tooling::fixit::getText(*Call->getArg(0), *Result.Context) + " + " +
       rewriteExprFromNumberToDuration(Result, *Scale, Binop->getRHS()) + ")")
          .str());
}

else {
  assert(Call == Binop->getRHS()->IgnoreParenImpCasts() &&
         "Call should be found on the RHS");
  Hint = FixItHint::CreateReplacement(
      Binop->getSourceRange(),
      (llvm::Twine(TimeFactory) + "(" +
       rewriteExprFromNumberToDuration(Result, *Scale, Binop->getLHS()) +
       " + " + tooling::fixit::getText(*Call->getArg(0), *Result.Context) +
       ")")
          .str());
}

if (const auto *Binop = Result.Nodes.getNodeAs<BinaryOperator>("binop")) {
  const auto *Arg = Result.Nodes.getNodeAs<Expr>("arg");
  const auto *InnerCall = Result.Nodes.getNodeAs<Expr>("inner_call");
  const Expr *LHS = Binop->getLHS();
  const Expr *RHS = Binop->getRHS();

  if (LHS->IgnoreParenImpCasts() == InnerCall) {
    Hint = FixItHint::CreateReplacement(
        OuterCall->getSourceRange(),
        (llvm::Twine(tooling::fixit::getText(*Arg, *Result.Context)) + " * " +
         tooling::fixit::getText(*RHS, *Result.Context))
            .str());
  } else {
    assert(RHS->IgnoreParenImpCasts() == InnerCall &&
           "Inner call should be find on the RHS");

    Hint = FixItHint::CreateReplacement(
        OuterCall->getSourceRange(),
        (llvm::Twine(tooling::fixit::getText(*LHS, *Result.Context)) + " * " +
         tooling::fixit::getText(*Arg, *Result.Context))
            .str());
  }
}

else if (const auto *Arg = Result.Nodes.getNodeAs<Expr>("arg")) {
  Hint = FixItHint::CreateReplacement(
      OuterCall->getSourceRange(),
      tooling::fixit::getText(*Arg, *Result.Context));
}

diag(OuterCall->getBeginLoc(),
     "remove unnecessary absl::Duration conversions")
    << Hint;

const auto *Op = Result.Nodes.getNodeAs<CXXOperatorCallExpr>("Op");
const auto *Call = Result.Nodes.getNodeAs<CallExpr>("Call");
assert(Op != nullptr && Call != nullptr && "Matcher does not work as expected");

if (Call->getNumArgs() == 1) {
  diag(Op->getBeginLoc(), "call to 'absl::StrCat' has no effect");
  return;
}

const auto *MatchedCall = Result.Nodes.getNodeAs<CallExpr>("call");
if (!MatchedCall)
  return;

const Expr *Arg = MatchedCall->getArg(0)->IgnoreImpCasts();
if (Arg->getBeginLoc().isMacroID())
  return;

std::optional<std::string> SimpleArg = stripFloatCast(Result, *Arg);
if (!SimpleArg)
  SimpleArg = stripFloatLiteralFraction(Result, *Arg);

if (SimpleArg) {
  diag(MatchedCall->getBeginLoc(), "use the integer version of absl::%0")
      << MatchedCall->getDirectCallee()->getName()
      << FixItHint::CreateReplacement(Arg->getSourceRange(), *SimpleArg);
}

static bool insideMacroDefinition(const MatchFinder::MatchResult &Result,
                                  SourceRange Range) {
  return !clang::Lexer::makeFileCharRange(
              clang::CharSourceRange::getCharRange(Range),
              *Result.SourceManager, Result.Context->getLangOpts())
              .isValid();
}

const auto *ArgExpr = Result.Nodes.getNodeAs<Expr>("arg");
SourceLocation Loc = ArgExpr->getBeginLoc();
const auto *OuterExpr = Result.Nodes.getNodeAs<Expr>("OuterExpr");

if (!match(isInTemplateInstantiation(), *OuterExpr, *Result.Context).empty()) {
  if (MatchedTemplateLocations.count(Loc) == 0) {
    diag(Loc, Message);
  }
  return;
}

internal::Matcher<Stmt> IsInsideTemplate =
    hasAncestor(decl(anyOf(classTemplateDecl(), functionTemplateDecl())));
if (!match(IsInsideTemplate, *ArgExpr, *Result.Context).empty())
  MatchedTemplateLocations.insert(Loc);

CharSourceRange SourceRange = Lexer::makeFileCharRange(
    CharSourceRange::getTokenRange(ArgExpr->getSourceRange()),
    *Result.SourceManager, Result.Context->getLangOpts());
if (SourceRange.isInvalid())
  return;

const auto *BinOp = Result.Nodes.getNodeAs<BinaryOperator>("binop");
std::string InverseName =
    Result.Nodes.getNodeAs<FunctionDecl>("func_decl")->getNameAsString();

std::optional<DurationScale> Scale = getScaleForTimeInverse(InverseName);
if (!Scale)
  return;

if (OuterCall) {
  if (insideMacroDefinition(Result, OuterCall->getSourceRange()))
    return;

  bool NeedParens = parensRequired(Result, OuterCall);

  emitDiagnostic(
      OuterCall,
      (llvm::Twine(NeedParens ? "(" : "") +
       rewriteExprFromNumberToTime(Result, *Scale, BinOp->getLHS()) + " - " +
       rewriteExprFromNumberToTime(Result, *Scale, BinOp->getRHS()) +
       (NeedParens ? ")" : ""))
          .str());
}

else {
  const auto *MaybeCallArg = selectFirst<const CallExpr>(
      "arg", match(expr(hasAncestor(
                   callExpr(callee(functionDecl(hasName(
                                getDurationFactoryForScale(*Scale)))))
                       .bind("arg"))),
               *BinOp, *Result.Context));
  if (MaybeCallArg && MaybeCallArg->getArg(0)->IgnoreImpCasts() == BinOp &&
      !insideMacroDefinition(Result, MaybeCallArg->getSourceRange())) {
    bool NeedParens = parensRequired(Result, MaybeCallArg);

    emitDiagnostic(
        MaybeCallArg,
        (llvm::Twine(NeedParens ? "(" : "") +
         rewriteExprFromNumberToTime(Result, *Scale, BinOp->getLHS()) +
         " - " +
         rewriteExprFromNumberToTime(Result, *Scale, BinOp->getRHS()) +
         (NeedParens ? ")" : ""))
            .str());
  } else {
    emitDiagnostic(
        BinOp,
        (llvm::Twine(
             getDurationInverseForScale(*Scale).second.str().substr(2)) +
         "(" + rewriteExprFromNumberToTime(Result, *Scale, BinOp->getLHS()) +
         " - " +
         rewriteExprFromNumberToTime(Result, *Scale, BinOp->getRHS()) + ")")
            .str());
  }
}

static bool insideMacroDefinition(const MatchFinder::MatchResult &Result,
                                SourceRange Range) {
  return !clang::Lexer::makeFileCharRange(
              clang::CharSourceRange::getCharRange(Range),
              *Result.SourceManager, Result.Context->getLangOpts())
              .isValid();
}

static bool parensRequired(const MatchFinder::MatchResult &Result,
                         const Expr *Node) {
  return !(isConstructorAssignment(Result, Node) || isArgument(Result, Node) ||
           isReturn(Result, Node));
}

const auto *Call = Result.Nodes.getNodeAs<CallExpr>("call");
if (Call->getExprLoc().isMacroID())
  return;

const Expr *Arg = Call->getArg(0)->IgnoreParenImpCasts();
if (Arg->getBeginLoc().isMacroID())
  return;

if (isLiteralZero(Result, *Arg)) {
  diag(Call->getBeginLoc(),
       "use ZeroDuration() for zero-length time intervals")
      << FixItHint::CreateReplacement(Call->getSourceRange(),
                                      "absl::ZeroDuration()");
  return;
}

const auto *CallDecl = Result.Nodes.getNodeAs<FunctionDecl>("call_decl");
std::optional<DurationScale> MaybeScale =
    getScaleForFactory(CallDecl->getName());
if (!MaybeScale)
  return;
DurationScale Scale = *MaybeScale;

if (const auto *MultBinOp =
        Result.Nodes.getNodeAs<BinaryOperator>("mult_binop")) {
  const auto *IntLit = llvm::dyn_cast<IntegerLiteral>(MultBinOp->getLHS());
  const auto *FloatLit = llvm::dyn_cast<FloatingLiteral>(MultBinOp->getLHS());
  if (IntLit || FloatLit) {
    NewScale = getNewScale(Scale, getValue(IntLit, FloatLit));
    if (NewScale)
      Remainder = MultBinOp->getRHS();
  }

  if (!NewScale) {
    IntLit = llvm::dyn_cast<IntegerLiteral>(MultBinOp->getRHS());
    FloatLit = llvm::dyn_cast<FloatingLiteral>(MultBinOp->getRHS());
    if (IntLit || FloatLit) {
      NewScale = getNewScale(Scale, getValue(IntLit, FloatLit));
      if (NewScale)
        Remainder = MultBinOp->getLHS();
    }
  }
}

else if (const auto *DivBinOp =
               Result.Nodes.getNodeAs<BinaryOperator>("div_binop")) {
  const auto *FloatLit = llvm::cast<FloatingLiteral>(DivBinOp->getRHS());
  std::optional<DurationScale> NewScale =
      getNewScale(Scale, 1.0 / FloatLit->getValueAsApproximateDouble());
  if (NewScale) {
    const Expr *Remainder = DivBinOp->getLHS();
    diag(Call->getBeginLoc(), "internal duration scaling can be removed")
        << FixItHint::CreateReplacement(
               Call->getSourceRange(),
               (llvm::Twine(getDurationFactoryForScale(*NewScale)) + "(" +
                tooling::fixit::getText(*Remainder, *Result.Context) + ")")
                   .str());
  }
}

if (NewScale) {
  assert(Remainder && "No remainder found");
  diag(Call->getBeginLoc(), "internal duration scaling can be removed")
      << FixItHint::CreateReplacement(
             Call->getSourceRange(),
             (llvm::Twine(getDurationFactoryForScale(*NewScale)) + "(" +
              tooling::fixit::getText(*Remainder, *Result.Context) + ")")
                 .str());
}

static std::optional<DurationScale>
getScaleForFactory(llvm::StringRef FactoryName) {
  return llvm::StringSwitch<std::optional<DurationScale>>(FactoryName)
      .Case("Nanoseconds", DurationScale::Nanoseconds)
      .Case("Microseconds", DurationScale::Microseconds)
      .Case("Milliseconds", DurationScale::Milliseconds)
      .Case("Seconds", DurationScale::Seconds)
      .Case("Minutes", DurationScale::Minutes)
      .Case("Hours", DurationScale::Hours)
      .Default(std::nullopt);
}

static double getValue(const IntegerLiteral *IntLit,
                     const FloatingLiteral *FloatLit) {
  if (IntLit)
    return IntLit->getValue().getLimitedValue();

  assert(FloatLit != nullptr && "Neither IntLit nor FloatLit set");
  return FloatLit->getValueAsApproximateDouble();
}

static std::optional<std::tuple<DurationScale, double>>
getNewScaleSingleStep(DurationScale OldScale, double Multiplier) {
  switch (OldScale) {
  case DurationScale::Hours:
    if (Multiplier <= 1.0 / 60.0)
      return std::make_tuple(DurationScale::Minutes, Multiplier * 60.0);
    break;

  case DurationScale::Minutes:
    if (Multiplier >= 60.0)
      return std::make_tuple(DurationScale::Hours, Multiplier / 60.0);
    if (Multiplier <= 1.0 / 60.0)
      return std::make_tuple(DurationScale::Seconds, Multiplier * 60.0);
    break;

  case DurationScale::Seconds:
    if (Multiplier >= 60.0)
      return std::make_tuple(DurationScale::Minutes, Multiplier / 60.0);
    if (Multiplier <= 1e-3)
      return std::make_tuple(DurationScale::Milliseconds, Multiplier * 1e3);
    break;

  case DurationScale::Milliseconds:
    if (Multiplier >= 1e3)
      return std::make_tuple(DurationScale::Seconds, Multiplier / 1e3);
    if (Multiplier <= 1e-3)
      return std::make_tuple(DurationScale::Microseconds, Multiplier * 1e3);
    break;

  case DurationScale::Microseconds:
    if (Multiplier >= 1e3)
      return std::make_tuple(DurationScale::Milliseconds, Multiplier / 1e3);
    if (Multiplier <= 1e-3)
      return std::make_tuple(DurationScale::Nanoseconds, Multiplier * 1e-3);
    break;

  case DurationScale::Nanoseconds:
    if (Multiplier >= 1e3)
      return std::make_tuple(DurationScale::Microseconds, Multiplier / 1e3);
    break;
  }

  return std::nullopt;
}

static std::optional<DurationScale> getNewScale(DurationScale OldScale,
                                              double Multiplier) {
  while (Multiplier != 1.0) {
    std::optional<std::tuple<DurationScale, double>> Result =
        getNewScaleSingleStep(OldScale, Multiplier);
    if (!Result)
      break;
    if (std::get<1>(*Result) == 1.0)
      return std::get<0>(*Result);
    Multiplier = std::get<1>(*Result);
    OldScale = std::get<0>(*Result);
  }

  return std::nullopt;
}

