if (!Replacement)
  return;

std::optional<std::string> makeCharacterLiteral(const StringLiteral *Literal) {
  std::string Result;
  {
    llvm::raw_string_ostream OS(Result);
    Literal->outputString(OS);
  }
  auto Pos = Result.find_first_of('"');
  if (Pos == Result.npos)
    return std::nullopt;
  Result[Pos] = '\'';
  Pos = Result.find_last_of('"');
  if (Pos == Result.npos)
    return std::nullopt;
  Result[Pos] = '\'';
  return Result;
}

