if (const Expr *NoexceptExpr = FuncDecl->getInstantiatedFromMemberFunction() ? 
    FuncDecl->getInstantiatedFromMemberFunction()->getType()->getAs<FunctionProtoType>()->getNoexceptSpecifier() :
    FuncDecl->getType()->getAs<FunctionProtoType>()->getNoexceptSpecifier()) {
