  diag(Initializer->getSourceLocation(),
       "move constructor initializes %select{class member|base class}0 by "
       "calling a copy constructor")
      << Initializer->isBaseInitializer();
  diag(CopyCtor->getLocation(), "copy constructor being called",
       DiagnosticIDs::Note);
  diag(Candidate->getLocation(), "candidate move constructor here",
       DiagnosticIDs::Note);
}

auto* Context = Result.Context;
if (Context->getDiagnostics().hasUncompilableErrorOccurred())
  return;

const SourceManager &SM = *Result.SourceManager;
const auto *VectorVarDecl = Result.Nodes.getNodeAs<VarDecl>(VectorVarDeclName);
const auto *ForLoop = Result.Nodes.getNodeAs<ForStmt>(LoopCounterName);
const auto *RangeLoop = Result.Nodes.getNodeAs<CXXForRangeStmt>(RangeLoopName);
const auto *VectorAppendCall = Result.Nodes.getNodeAs<CXXMemberCallExpr>(PushBackOrEmplaceBackCallName);
const auto *ProtoVarDecl = Result.Nodes.getNodeAs<VarDecl>(ProtoVarDeclName);
const auto *ProtoAddFieldCall = Result.Nodes.getNodeAs<CXXMemberCallExpr>(ProtoAddFieldCallName);
const auto *LoopEndExpr = Result.Nodes.getNodeAs<Expr>(LoopEndExprName);
const auto *LoopParent = Result.Nodes.getNodeAs<CompoundStmt>(LoopParentName);

const CXXMemberCallExpr *AppendCall = VectorAppendCall ? VectorAppendCall : ProtoAddFieldCall;
assert(AppendCall && "no append call expression");

const Stmt *LoopStmt = ForLoop;
if (!LoopStmt)
  LoopStmt = RangeLoop;

const auto *TargetVarDecl = VectorVarDecl;
if (!TargetVarDecl)
  TargetVarDecl = ProtoVarDecl;

llvm::SmallPtrSet<const DeclRefExpr *, 16> AllVarRefs =
    utils::decl_ref_expr::allDeclRefExprs(*TargetVarDecl, *LoopParent,
                                          *Context);
for (const auto *Ref : AllVarRefs) {
  if (SM.isBeforeInTranslationUnit(Ref->getLocation(),
                                   LoopStmt->getBeginLoc())) {
    return;
  }
}

std::string PartialReserveStmt;
if (VectorAppendCall != nullptr) {
  PartialReserveStmt = ".reserve";
} else {
  llvm::StringRef FieldName = ProtoAddFieldCall->getMethodDecl()->getName();
  FieldName.consume_front("add_");
  std::string MutableFieldName = ("mutable_" + FieldName).str();
  PartialReserveStmt = "." + MutableFieldName +
                       "()->Reserve"; // e.g., ".mutable_xxx()->Reserve"
}

std::string ReserveSize;
if (RangeLoop) {
  StringRef RangeInitExpName =
      Lexer::getSourceText(CharSourceRange::getTokenRange(
                               RangeLoop->getRangeInit()->getSourceRange()),
                           SM, Context->getLangOpts());
  ReserveSize = (RangeInitExpName + ".size()").str();
} else if (ForLoop) {
  StringRef LoopEndSource = Lexer::getSourceText(
      CharSourceRange::getTokenRange(LoopEndExpr->getSourceRange()), SM,
      Context->getLangOpts());
  ReserveSize = std::string(LoopEndSource);
}

auto Diag = diag(AppendCall->getBeginLoc(),
               "%0 is called inside a loop; consider pre-allocating the "
               "container capacity before the loop")
            << AppendCall->getMethodDecl()->getDeclName();
if (!ReserveSize.empty()) {
  std::string ReserveStmt =
      (VarName + PartialReserveStmt + "(" + ReserveSize + ");\n").str();
  Diag << FixItHint::CreateInsertion(LoopStmt->getBeginLoc(), ReserveStmt);
}

const auto *NewVar = Result.Nodes.getNodeAs<VarDecl>("newVarDecl");
const auto *OldVar = Result.Nodes.getNodeAs<VarDecl>(OldVarDeclId);
const auto *ObjectArg = Result.Nodes.getNodeAs<VarDecl>(ObjectArgId);
const auto *BlockStmt = Result.Nodes.getNodeAs<Stmt>("blockStmt");
const auto *CtorCall = Result.Nodes.getNodeAs<CXXConstructExpr>("ctorCall");
const auto *Stmt = Result.Nodes.getNodeAs<DeclStmt>("declStmt");

for (unsigned int I = 1; I < CtorCall->getNumArgs(); ++I)
  if (!CtorCall->getArg(I)->isDefaultArgument())
    return;

if (differentReplacedTemplateParams(
        NewVar->getType(), constructorArgumentType(OldVar, Result.Nodes),
        *Result.Context))
  return;

if (OldVar == nullptr) {
  handleCopyFromMethodReturn(*NewVar, *BlockStmt, *Stmt, IssueFix, ObjectArg,
                             *Result.Context);
} else {
  handleCopyFromLocalVar(*NewVar, *OldVar, *BlockStmt, *Stmt, IssueFix,
                          *Result.Context);
}

bool differentReplacedTemplateParams(const QualType &VarType,
                                     const QualType &InitializerType,
                                     ASTContext &Context) {
  if (const SubstTemplateTypeParmType *VarTmplType =
          getSubstitutedType(VarType, Context)) {
    if (const SubstTemplateTypeParmType *InitializerTmplType =
            getSubstitutedType(InitializerType, Context)) {
      const TemplateTypeParmDecl *VarTTP = VarTmplType->getReplacedParameter();
      const TemplateTypeParmDecl *InitTTP =
          InitializerTmplType->getReplacedParameter();
      return (VarTTP->getDepth() != InitTTP->getDepth() ||
              VarTTP->getIndex() != InitTTP->getIndex() ||
              VarTTP->isParameterPack() != InitTTP->isParameterPack());
    }
  }
  return false;
}

QualType constructorArgumentType(const VarDecl *OldVar,
                              const BoundNodes &Nodes) {
  if (OldVar) {
    return OldVar->getType();
  }
  if (const auto *FuncDecl = Nodes.getNodeAs<FunctionDecl>(FunctionDeclId)) {
    return FuncDecl->getReturnType();
  }
  const auto *MethodDecl = Nodes.getNodeAs<CXXMethodDecl>(MethodDeclId);
  return MethodDecl->getReturnType();
}

const auto *Definition = Result.Nodes.getNodeAs<CXXMethodDecl>("x");
if (!Definition)
  return;

if (Definition->isConst()) {
  SourceRange DefConst = getLocationOfConst(Definition->getTypeSourceInfo(),
                                            *Result.SourceManager,
                                            Result.Context->getLangOpts());
  if (DefConst.isInvalid())
    return;

if (Declaration != Definition) {
  SourceRange DeclConst = getLocationOfConst(Declaration->getTypeSourceInfo(),
                                             *Result.SourceManager,
                                             Result.Context->getLangOpts());
  if (DeclConst.isInvalid())
    return;
  Diag << FixItHint::CreateRemoval(DeclConst);
}

static StringRef getStringFromRange(SourceManager &SourceMgr,
                                    const LangOptions &LangOpts,
                                    SourceRange Range) {
  if (SourceMgr.getFileID(Range.getBegin()) !=
      SourceMgr.getFileID(Range.getEnd()))
    return {};

  return Lexer::getSourceText(CharSourceRange(Range, true), SourceMgr,
                              LangOpts);
}

static SourceRange getLocationOfConst(const TypeSourceInfo *TSI,
                                      SourceManager &SourceMgr,
                                      const LangOptions &LangOpts) {
  assert(TSI);
  const auto FTL = TSI->getTypeLoc().IgnoreParens().getAs<FunctionTypeLoc>();
  assert(FTL);

  SourceRange Range{FTL.getRParenLoc().getLocWithOffset(1),
                    FTL.getLocalRangeEnd()};
  StringRef Text = getStringFromRange(SourceMgr, LangOpts, Range);
  size_t Offset = Text.find("const");
  if (Offset == StringRef::npos)
    return {};

  SourceLocation Start = Range.getBegin().getLocWithOffset(Offset);
  return {Start, Start.getLocWithOffset(strlen("const") - 1)};
}

SourceManager &SM = *Result.SourceManager;
const auto *FirstDecl = cast<CXXMethodDecl>(MatchedDecl->getFirstDecl());
const SourceLocation FirstDeclEnd = utils::lexer::findNextTerminator(
    FirstDecl->getEndLoc(), SM, getLangOpts());
const CharSourceRange SecondDeclRange = CharSourceRange::getTokenRange(
    MatchedDecl->getBeginLoc(),
    utils::lexer::findNextTerminator(MatchedDecl->getEndLoc(), SM,
                                     getLangOpts()));
if (FirstDeclEnd.isInvalid() || SecondDeclRange.isInvalid())
  return;

const auto *Var = Result.Nodes.getNodeAs<VarDecl>("vardecl");
const auto *CtorCall = Result.Nodes.getNodeAs<Expr>("ctor_call");
if (!Var || !CtorCall)
  return;

const auto *Param = Result.Nodes.getNodeAs<ParmVarDecl>("param");
const auto *Function = Result.Nodes.getNodeAs<FunctionDecl>("functionDecl");
if (!Param || !Function)
  return;

FunctionParmMutationAnalyzer &Analyzer =
    MutationAnalyzers.try_emplace(Function, *Function, *Result.Context)
        .first->second;
if (Analyzer.isMutated(Param))
  return;

if (!IsConstQualified) {
  auto AllDeclRefExprs = utils::decl_ref_expr::allDeclRefExprs(
      *Param, *Function, *Result.Context);
  if (AllDeclRefExprs.size() == 1) {
    auto CanonicalType = Param->getType().getCanonicalType();
    const auto &DeclRefExpr = **AllDeclRefExprs.begin();

    if (!hasLoopStmtAncestor(DeclRefExpr, *Function, *Result.Context) &&
        ((utils::type_traits::hasNonTrivialMoveConstructor(CanonicalType) &&
          utils::decl_ref_expr::isCopyConstructorArgument(
              DeclRefExpr, *Function, *Result.Context)) ||
         (utils::type_traits::hasNonTrivialMoveAssignment(CanonicalType) &&
          utils::decl_ref_expr::isCopyAssignmentArgument(
              DeclRefExpr, *Function, *Result.Context)))) {
      handleMoveFix(*Param, DeclRefExpr, *Result.Context);
      return;
    }
  }
}

const auto *Method = llvm::dyn_cast<CXXMethodDecl>(Function);
if (Param->getBeginLoc().isMacroID() || (Method && Method->isVirtual()) ||
    isReferencedOutsideOfCallExpr(*Function, *Result.Context) ||
    (Function->getTemplatedKind() != FunctionDecl::TK_NonTemplate))
  return;

for (const auto *FunctionDecl = Function; FunctionDecl != nullptr;
     FunctionDecl = FunctionDecl->getPreviousDecl()) {
  const auto &CurrentParam = *FunctionDecl->getParamDecl(Index);
  Diag << utils::fixit::changeVarDeclToReference(CurrentParam,
                                                 *Result.Context);
  if (!CurrentParam.getType().getCanonicalType().isConstQualified()) {
    if (std::optional<FixItHint> Fix = utils::fixit::addQualifierToVarDecl(
            CurrentParam, *Result.Context, DeclSpec::TQ::TQ_const))
      Diag << *Fix;
  }
}

bool isReferencedOutsideOfCallExpr(const FunctionDecl &Function,
                                 ASTContext &Context) {
  auto Matches = match(declRefExpr(to(functionDecl(equalsNode(&Function))),
                                   unless(hasAncestor(callExpr()))),
                       Context);
  return !Matches.empty();
}

bool hasLoopStmtAncestor(const DeclRefExpr &DeclRef, const Decl &Decl,
                         ASTContext &Context) {
  auto Matches = match(
      traverse(TK_AsIs,
               decl(forEachDescendant(declRefExpr(
                   equalsNode(&DeclRef),
                   unless(hasAncestor(stmt(anyOf(forStmt(), cxxForRangeStmt(),
                                                 whileStmt(), doStmt())))))))),
      Decl, Context);
  return Matches.empty();
}

std::string paramNameOrIndex(StringRef Name, size_t Index) {
  return (Name.empty() ? llvm::Twine('#') + llvm::Twine(Index + 1)
                       : llvm::Twine('\'') + Name + llvm::Twine('\''))
      .str();
}

static llvm::StringSet<> Cpp11OnlyFns = {
    "acosh", "asinh", "atanh", "cbrt", "copysign", "erf",
    "erfc", "exp2", "expm1", "fdim", "fma", "fmax",
    "fmin", "hypot", "ilogb", "lgamma", "llrint", "llround",
    "log1p", "log2", "logb", "lrint", "lround", "nearbyint",
    "nextafter", "nexttoward", "remainder", "remquo", "rint", "round",
    "scalbln", "scalbn", "tgamma", "trunc"};
bool StdFnRequiresCpp11 = Cpp11OnlyFns.count(OldFnName);

std::string NewFnName;
bool FnInCmath = false;
if (getLangOpts().CPlusPlus &&
    (!StdFnRequiresCpp11 || getLangOpts().CPlusPlus11)) {
  NewFnName = ("std::" + OldFnName).str();
  FnInCmath = true;
} else {
  NewFnName = (OldFnName + "f").str();
}

if (FnInCmath)
  Diag << IncludeInserter.createIncludeInsertion(
      Result.Context->getSourceManager().getFileID(Call->getBeginLoc()),
      "<cmath>");

AST_MATCHER_P(Type, isBuiltinType, BuiltinType::Kind, Kind) {
  if (const auto *BT = dyn_cast<BuiltinType>(&Node)) {
    return BT->getKind() == Kind;
  }
  return false;
}

const auto *CallMove = Result.Nodes.getNodeAs<CallExpr>("call-move");
const auto *ReceivingExpr = Result.Nodes.getNodeAs<Expr>("receiving-expr");
const auto *InvocationParm = Result.Nodes.getNodeAs<ParmVarDecl>("invocation-parm");
const auto *InvocationParmType = Result.Nodes.getNodeAs<QualType>("invocation-parm-type");

if (!ReceivingExpr && AlreadyCheckedMoves.contains(CallMove))
  return;

if (ReceivingExpr)
  AlreadyCheckedMoves.insert(CallMove);

const Expr *Arg = CallMove->getArg(0);
const QualType ArgType = Arg->getType().getCanonicalType();
SourceManager &SM = Result.Context->getSourceManager();

CharSourceRange MoveRange = CharSourceRange::getCharRange(CallMove->getSourceRange());
CharSourceRange FileMoveRange = Lexer::makeFileCharRange(MoveRange, SM, getLangOpts());
if (!FileMoveRange.isValid())
  return;

if (const CXXRecordDecl *R = ArgType->getAsCXXRecordDecl()) {
  if (R->isLambda())
    return;
  for (const auto *Ctor : R->ctors()) {
    if (Ctor->isCopyConstructor() && Ctor->isDeleted())
      return;
  }
}

bool IsVariable = isa<DeclRefExpr>(Arg);
bool IsRVRefParam = IsRValueReferenceParam(ReceivingExpr, InvocationParmType, Arg);
const auto *Var = IsVariable ? dyn_cast<DeclRefExpr>(Arg)->getDecl() : nullptr;

if (IsRVRefParam) {
  const auto *ReceivingCallExpr = dyn_cast<CallExpr>(ReceivingExpr);
  const auto *ReceivingConstructExpr = dyn_cast<CXXConstructExpr>(ReceivingExpr);
  if ((!ReceivingCallExpr || !ReceivingCallExpr->getDirectCallee() ||
       ReceivingCallExpr->getDirectCallee()->isTemplateInstantiation()) &&
      (!ReceivingConstructExpr ||
       !ReceivingConstructExpr->getConstructor() ||
       ReceivingConstructExpr->getConstructor()->isTemplateInstantiation()))
    return;

  const NamedDecl *FunctionName = nullptr;
  FunctionName =
      ReceivingCallExpr
          ? ReceivingCallExpr->getDirectCallee()->getUnderlyingDecl()
          : ReceivingConstructExpr->getConstructor()->getUnderlyingDecl();

  QualType NoRefType = (*InvocationParmType)->getPointeeType();
  PrintingPolicy PolicyWithSuppressedTag(getLangOpts());
  PolicyWithSuppressedTag.SuppressTagKeyword = true;
  PolicyWithSuppressedTag.SuppressUnwrittenScope = true;
  std::string ExpectParmTypeName =
      NoRefType.getAsString(PolicyWithSuppressedTag);
  if (!NoRefType->isPointerType()) {
    NoRefType.addConst();
    ExpectParmTypeName =
        NoRefType.getAsString(PolicyWithSuppressedTag) + " &";
  }

  diag(InvocationParm->getLocation(),
       "consider changing the %ordinal0 parameter of %1 from %2 to '%3'",
       DiagnosticIDs::Note)
      << (InvocationParm->getFunctionScopeIndex() + 1) << FunctionName
      << *InvocationParmType << ExpectParmTypeName;
}

else if (ReceivingExpr && CheckMoveToConstRef) {
  if ((*InvocationParmType)->isRValueReferenceType())
    return;

  auto Diag = diag(FileMoveRange.getBegin(),
                   "passing result of std::move() as a const reference "
                   "argument; no move will actually happen");
  replaceCallWithArg(CallMove, Diag, SM, getLangOpts());

  if (const CXXRecordDecl *RecordDecl = ArgType->getAsCXXRecordDecl();
      RecordDecl && !(RecordDecl->hasMoveConstructor() &&
                      RecordDecl->hasMoveAssignment())) {
    const bool MissingMoveAssignment = !RecordDecl->hasMoveAssignment();
    const bool MissingMoveConstructor = !RecordDecl->hasMoveConstructor();
    const bool MissingBoth = MissingMoveAssignment && MissingMoveConstructor;

    diag(RecordDecl->getLocation(),
         "%0 is not move "
         "%select{|assignable}1%select{|/}2%select{|constructible}3",
         DiagnosticIDs::Note)
        << RecordDecl << MissingMoveAssignment << MissingBoth
        << MissingMoveConstructor;
  }
}

static void replaceCallWithArg(const CallExpr *Call, DiagnosticBuilder &Diag,
                               const SourceManager &SM,
                               const LangOptions &LangOpts) {
  const Expr *Arg = Call->getArg(0);

  CharSourceRange BeforeArgumentsRange = Lexer::makeFileCharRange(
      CharSourceRange::getCharRange(Call->getBeginLoc(), Arg->getBeginLoc()),
      SM, LangOpts);
  CharSourceRange AfterArgumentsRange = Lexer::makeFileCharRange(
      CharSourceRange::getCharRange(Call->getEndLoc(),
                                    Call->getEndLoc().getLocWithOffset(1)),
      SM, LangOpts);

  if (BeforeArgumentsRange.isValid() && AfterArgumentsRange.isValid()) {
    Diag << FixItHint::CreateRemoval(BeforeArgumentsRange)
         << FixItHint::CreateRemoval(AfterArgumentsRange);
  }
}

bool IsRValueReferenceParam(const Expr *Invocation,
                            const QualType *InvocationParmType,
                            const Expr *Arg) {
  if (Invocation && (*InvocationParmType)->isRValueReferenceType() &&
      Arg->isLValue()) {
    if (!Invocation->getType()->isRecordType())
      return true;
    else {
      if (const auto *ConstructCallExpr =
              dyn_cast<CXXConstructExpr>(Invocation)) {
        if (const auto *ConstructorDecl = ConstructCallExpr->getConstructor()) {
          if (!ConstructorDecl->isCopyOrMoveConstructor() &&
              !ConstructorDecl->isDefaultConstructor())
            return true;
        }
      }
    }
  }
  return false;
}

const auto *VD = Result.Nodes.getNodeAs<VarDecl>("faulty-var");
const auto *Init = Result.Nodes.getNodeAs<Expr>("init");
const auto *OperatorCall = Result.Nodes.getNodeAs<Expr>("operator-call");

const auto *Materialized = dyn_cast<MaterializeTemporaryExpr>(Init);
if (!Materialized)
