if (Destructor->getAccess() == AccessSpecifier::AS_private) {
  diag(MatchedClassOrStruct->getLocation(),
       "destructor of %0 is private and prevents using the type")
      << MatchedClassOrStruct;
  diag(MatchedClassOrStruct->getLocation(),
