  const auto *NumTy = Result.Nodes.getNodeAs<Type>("num-type");
  const auto *DenomTy = Result.Nodes.getNodeAs<Type>("denom-type");
  const auto *ElementTy = Result.Nodes.getNodeAs<Type>("elem-type");
