    if (OtherCtor->isDeleted() || OtherCtor->getAccess() == AS_private)
      (OtherCtor->isCopyConstructor() ? DisabledCopy : DisabledMove) = true;
    else
      (OtherCtor->isCopyConstructor() ? EnabledCopy : EnabledMove) = true;
