static llvm::APFloat getHalf(const llvm::fltSemantics &Semantics) {
  return llvm::APFloat(Semantics, 1U) / llvm::APFloat(Semantics, 2U);
}

AST_MATCHER(FloatingLiteral, floatHalf) {
