static void replaceMoveWithForward(const UnresolvedLookupExpr *Callee,
                                   const ParmVarDecl *ParmVar,
                                   const TemplateTypeParmDecl *TypeParmDecl,
                                   DiagnosticBuilder &Diag,
                                   const ASTContext &Context) {
  const SourceManager &SM = Context.getSourceManager();
  const LangOptions &LangOpts = Context.getLangOpts();

  CharSourceRange CallRange =
      Lexer::makeFileCharRange(CharSourceRange::getTokenRange(
                                   Callee->getBeginLoc(), Callee->getEndLoc()),
                               SM, LangOpts);

  if (CallRange.isValid()) {
    const std::string TypeName =
        (TypeParmDecl->getIdentifier() && !TypeParmDecl->isImplicit())
            ? TypeParmDecl->getName().str()
            : (llvm::Twine("decltype(") + ParmVar->getName() + ")").str();

    const std::string ForwardName =
        (llvm::Twine("forward<") + TypeName + ">").str();

    NestedNameSpecifier *NNS = Callee->getQualifier();
    if (!NNS) {
      Diag << FixItHint::CreateReplacement(CallRange, "std::" + ForwardName);
    } else if (const NamespaceDecl *Namespace = NNS->getAsNamespace()) {
      if (Namespace->getName() == "std") {
        if (!NNS->getPrefix()) {
          Diag << FixItHint::CreateReplacement(CallRange,
                                               "std::" + ForwardName);
        } else if (NNS->getPrefix()->getKind() == NestedNameSpecifier::Global) {
          Diag << FixItHint::CreateReplacement(CallRange,
                                               "::std::" + ForwardName);
        }
      }
    }
  }
}

const auto *If = Result.Nodes.getNodeAs<IfStmt>("if");
if (const auto *E = Result.Nodes.getNodeAs<Expr>("expr")) {
  // ... (further processing follows)
}

const auto M =
    ignoringParenImpCasts(anyOf(declRefExpr(to(equalsNode(D))),
                                memberExpr(hasDeclaration(equalsNode(D)))));

if (!match(
         findAll(callExpr(hasAnyArgument(ignoringParenImpCasts(RefMatcher)))),
         *If, *Result.Context)
           .empty())
  return;

if (!match(
         findAll(cxxDeleteExpr(has(ignoringParenImpCasts(expr(RefMatcher))))),
         *If, *Result.Context)
           .empty())
  return;

if (llvm::any_of(MI->tokens(), [](const Token &T) {
      return T.isOneOf(tok::kw_if, tok::kw_else, tok::kw_switch, tok::kw_case,
                       tok::kw_break, tok::kw_while, tok::kw_do, tok::kw_for,
                       tok::kw_continue, tok::kw_goto, tok::kw_return);
    }))
  return;

for (unsigned ArgNo = 0U; ArgNo < MI->getNumParams(); ++ArgNo) {
  const IdentifierInfo *Arg = *(MI->param_begin() + ArgNo);
  const Token *ResultArgToks = Args->getUnexpArgument(ArgNo);

  if (hasSideEffects(ResultArgToks) &&
      countArgumentExpansions(MI, Arg) >= 2) {
    Check.diag(ResultArgToks->getLocation(),
               "side effects in the %ordinal0 macro argument %1 are "
               "repeated in macro expansion")
        << (ArgNo + 1) << Arg;
    Check.diag(MI->getDefinitionLoc(), "macro %0 defined here",
               DiagnosticIDs::Note)
        << MacroNameTok.getIdentifierInfo();
  }
}

unsigned MacroRepeatedPPCallbacks::countArgumentExpansions(
    const MacroInfo *MI, const IdentifierInfo *Arg) const {
  unsigned Current = 0;
  unsigned Max = 0;
  bool SkipParen = false;
  int SkipParenCount = 0;
  bool FoundBuiltin = false;
  bool PrevTokenIsHash = false;
  std::stack<unsigned, SmallVector<unsigned, 8>> CountAtQuestion;
  for (const auto &T : MI->tokens()) {
    if (FoundBuiltin && T.isOneOf(tok::question, tok::ampamp, tok::pipepipe))
      return Max;

    if (T.is(tok::hash)) {
      PrevTokenIsHash = true;
      continue;
    }
    if (PrevTokenIsHash) {
      PrevTokenIsHash = false;
      continue;
    }

    if (T.is(tok::question)) {
      CountAtQuestion.push(Current);
    } else if (T.is(tok::colon)) {
      if (CountAtQuestion.empty())
        return 0;
      Current = CountAtQuestion.top();
      CountAtQuestion.pop();
    }

    if (SkipParen) {
      if (T.is(tok::l_paren))
        SkipParenCount++;
      else if (T.is(tok::r_paren))
        SkipParenCount--;
      SkipParen = (SkipParenCount != 0);
      if (SkipParen)
        continue;
    }

    IdentifierInfo *TII = T.getIdentifierInfo();
    if (TII == nullptr)
      continue;

    if (TII->getBuiltinID() == Builtin::BI__builtin_constant_p) {
      FoundBuiltin = true;
      SkipParen = true;
      continue;
    }

    if (TII->hasMacroDefinition()) {
      const MacroInfo *M = PP.getMacroDefinition(TII).getMacroInfo();
      if (M != nullptr && M->isFunctionLike())
        SkipParen = true;
      continue;
    }

    if (TII == Arg) {
      Current++;
      if (Current > Max)
        Max = Current;
    }
  }
  return Max;
}

bool MacroRepeatedPPCallbacks::hasSideEffects(
    const Token *ResultArgToks) const {
  for (; ResultArgToks->isNot(tok::eof); ++ResultArgToks) {
    if (ResultArgToks->isOneOf(tok::plusplus, tok::minusminus))
      return true;
  }
  return false;
}

SharedPtrArrayMismatchCheck::SmartPtrClassMatcher
SharedPtrArrayMismatchCheck::getSmartPointerClassMatcher() const {
  return classTemplateSpecializationDecl(
      hasName("::std::shared_ptr"), templateArgumentCountIs(1),
      hasTemplateArgument(
          0, templateArgument(refersToType(qualType().bind(PointerTypeN)))));
}

SharedPtrArrayMismatchCheck::SharedPtrArrayMismatchCheck(
    StringRef Name, ClangTidyContext *Context)
    : SmartPtrArrayMismatchCheck(Name, Context, "shared") {}

const auto *FunctionExpr = Result.Nodes.getNodeAs<CallExpr>(FunctionExprName);
if (FunctionExpr->getBeginLoc().isMacroID())
  return;

if (WantToUseSafeFunctions && PP->isMacroDefined("__STDC_LIB_EXT1__")) {
  std::optional<bool> AreSafeFunctionsWanted;
  Preprocessor::macro_iterator It = PP->macro_begin();
  while (It != PP->macro_end() && !AreSafeFunctionsWanted) {
    if (It->first->getName() == "__STDC_WANT_LIB_EXT1__") {
      const auto *MI = PP->getMacroInfo(It->first);
      if (MI) {
        const auto &T = MI->tokens().back();
        if (T.isLiteral() && T.getLiteralData()) {
          StringRef ValueStr = StringRef(T.getLiteralData(), T.getLength());
          llvm::APInt IntValue;
          ValueStr.getAsInteger(10, IntValue);
          AreSafeFunctionsWanted = IntValue.getZExtValue();
        }
      }
    }
    ++It;
  }
  if (AreSafeFunctionsWanted)
    UseSafeFunctions = *AreSafeFunctionsWanted;
}

StringRef Name = FunctionExpr->getDirectCallee()->getName();
if (Name.startswith("mem") || Name.startswith("wmem"))
  memoryHandlerFunctionFix(Name, Result);
else if (Name == "strerror_s")
  strerror_sFix(Result);
else if (Name.endswith("ncmp"))
  ncmpFix(Name, Result);
else if (Name.endswith("xfrm"))
  xfrmFix(Name, Result);

void NotNullTerminatedResultCheck::memoryHandlerFunctionFix(
    StringRef Name, const MatchFinder::MatchResult &Result) {
  if (isCorrectGivenLength(Result))
    return;

  if (Name.endswith("chr")) {
    memchrFix(Name, Result);
    return;
  }

  if ((Name.contains("cpy") || Name.contains("move")) &&
      (isDestAndSrcEquals(Result) || isFixedGivenLengthAndUnknownSrc(Result)))
    return;

  auto Diag =
      diag(Result.Nodes.getNodeAs<CallExpr>(FunctionExprName)->getBeginLoc(),
           "the result from calling '%0' is not null-terminated")
      << Name;

  if (Name.endswith("cpy")) {
    memcpyFix(Name, Result, Diag);
  } else if (Name.endswith("cpy_s")) {
    memcpy_sFix(Name, Result, Diag);
  } else if (Name.endswith("move")) {
    memmoveFix(Name, Result, Diag);
  } else if (Name.endswith("move_s")) {
    isDestCapacityFix(Result, Diag);
    lengthArgHandle(LengthHandleKind::Increase, Result, Diag);
  }
}

static const Expr *getDestCapacityExpr(const MatchFinder::MatchResult &Result) {
  if (const auto *DestMalloc = Result.Nodes.getNodeAs<Expr>(DestMallocExprName))
    return DestMalloc;

  if (const auto *DestVAT =
          Result.Nodes.getNodeAs<VariableArrayType>(DestArrayTyName))
    return DestVAT->getSizeExpr();

  if (const auto *DestVD = Result.Nodes.getNodeAs<VarDecl>(DestVarDeclName))
    if (const TypeLoc DestTL = DestVD->getTypeSourceInfo()->getTypeLoc())
      if (const auto DestCTL = DestTL.getAs<ConstantArrayTypeLoc>())
        return DestCTL.getSizeExpr();

  return nullptr;
}

static bool isDestAndSrcEquals(const MatchFinder::MatchResult &Result) {
  if (const auto *DestDRE = Result.Nodes.getNodeAs<DeclRefExpr>(DestExprName))
    if (const auto *SrcDRE = Result.Nodes.getNodeAs<DeclRefExpr>(SrcExprName))
      return DestDRE->getDecl()->getCanonicalDecl() ==
             SrcDRE->getDecl()->getCanonicalDecl();

  return false;
}

static bool
isGivenLengthEqualToSrcLength(const MatchFinder::MatchResult &Result) {
  if (Result.Nodes.getNodeAs<Expr>(UnknownLengthName))
    return false;

  if (isStringDataAndLength(Result))
    return true;

  int GivenLength = getGivenLength(Result);
  int SrcLength = getLength(Result.Nodes.getNodeAs<Expr>(SrcExprName), Result);

  if (GivenLength != 0 && SrcLength != 0 && GivenLength == SrcLength)
    return true;

  if (const auto *LengthExpr = Result.Nodes.getNodeAs<Expr>(LengthExprName))
    if (isa<BinaryOperator>(LengthExpr->IgnoreParenImpCasts()))
      return false;

  if (const CallExpr *StrlenCE = getStrlenExpr(Result))
    if (const auto *ArgDRE =
            dyn_cast<DeclRefExpr>(StrlenCE->getArg(0)->IgnoreImpCasts()))
      if (const auto *SrcVD = Result.Nodes.getNodeAs<VarDecl>(SrcVarDeclName))
        return dyn_cast<VarDecl>(ArgDRE->getDecl()) == SrcVD;

  return false;
}

static void lengthExprHandle(const Expr *LengthExpr,
                             LengthHandleKind LengthHandle,
                             const MatchFinder::MatchResult &Result,
                             DiagnosticBuilder &Diag) {
  LengthExpr = LengthExpr->IgnoreParenImpCasts();
  bool IsMacroDefinition = false;
  StringRef LengthExprStr = exprToStr(LengthExpr, Result);
  Preprocessor::macro_iterator It = PP->macro_begin();
  while (It != PP->macro_end() && !IsMacroDefinition) {
    if (It->first->getName() == LengthExprStr)
      IsMacroDefinition = true;
    ++It;
  }

  if (!IsMacroDefinition && isa<IntegerLiteral>(LengthExpr)) {
    size_t NewLength = cast<IntegerLiteral>(LengthExpr)->getValue().getZExtValue() +
                       (LengthHandle == LengthHandleKind::Increase ? 1 : -1);
    Diag << FixItHint::CreateReplacement(
        LengthExpr->getSourceRange(),
        (Twine(NewLength) + (isInjectUL(Result) ? "UL" : "")).str());
    return;
  }

  const auto *BO = dyn_cast<BinaryOperator>(LengthExpr);
  if (BO && BO->getOpcode() == BO_Add &&
      LengthHandle == LengthHandleKind::Decrease) {
    const Expr *LhsExpr = BO->getLHS()->IgnoreImpCasts();
    const Expr *RhsExpr = BO->getRHS()->IgnoreImpCasts();

    if (const auto *LhsIL = dyn_cast<IntegerLiteral>(LhsExpr)) {
      if (LhsIL->getValue().getZExtValue() == 1) {
        Diag << FixItHint::CreateRemoval(
            {LhsIL->getBeginLoc(),
             RhsExpr->getBeginLoc().getLocWithOffset(-1)});
        return;
      }
    }

    if (const auto *RhsIL = dyn_cast<IntegerLiteral>(RhsExpr)) {
      if (RhsIL->getValue().getZExtValue() == 1) {
        Diag << FixItHint::CreateRemoval(
            {LhsExpr->getEndLoc().getLocWithOffset(1), RhsIL->getEndLoc()});
        return;
      }
    }
  }

  bool NeedInnerParen = BO && BO->getOpcode() != BO_Add;
  if (NeedInnerParen)
    Diag << FixItHint::CreateInsertion(LengthExpr->getBeginLoc(), "(");

  SmallString<8> Injection;
  if (NeedInnerParen)
    Injection += ')';
  Injection += LengthHandle == LengthHandleKind::Increase ? " + 1" : " - 1";
  if (isInjectUL(Result))
    Injection += "UL";

  Diag << FixItHint::CreateInsertion(exprLocEnd(LengthExpr, Result), Injection);
}

const auto *Var = Result.Nodes.getNodeAs<VarDecl>("var");
if (!Var)
  return;

SourceLocation Loc = Var->getLocation();
if (!Loc.isValid())
  return;

if (!utils::isPresumedLocInHeaderFile(Loc, *Result.SourceManager,
                                 HeaderFileExtensions))
  return;

AST_MATCHER(clang::VarDecl, hasConstantDeclaration) {
  const Expr *Init = Node.getInit();
  if (Init && !Init->isValueDependent()) {
    if (Node.isConstexpr())
      return true;
    return Node.evaluateValue();
  }
  return false;
}

if (const auto *SL = Result.Nodes.getNodeAs<StringLiteral>("strlit")) {
  for (size_t Offset = 0, Length = SL->getLength(); Offset < Length; ++Offset) {
    if (Offset + 3 < Length && SL->getCodeUnit(Offset) == '\0' &&
        SL->getCodeUnit(Offset + 1) == 'x' &&
        isDigit(SL->getCodeUnit(Offset + 2)) &&
        isDigit(SL->getCodeUnit(Offset + 3))) {
      diag(SL->getBeginLoc(), "suspicious embedded NUL character");
      return;
    }
  }
}

if (const auto *SL = Result.Nodes.getNodeAs<StringLiteral>("truncated")) {
  diag(SL->getBeginLoc(),
       "truncated string literal with embedded NUL character");
}

AST_MATCHER(StringLiteral, containsNul) {
  for (size_t I = 0; I < Node.getLength(); ++I)
    if (Node.getCodeUnit(I) == '\0')
      return true;
  return false;
}

diag(TemporaryExpr->getBeginLoc(), "suspicious exception object created but "
                                   "not thrown; did you mean 'throw %0'?")
    << TemporaryExpr->getType().getBaseTypeIdentifier()->getName();

AST_MATCHER(CXXCatchStmt, isInMacro) {
  return Node.getBeginLoc().isMacroID() || Node.getEndLoc().isMacroID() ||
         Node.getCatchLoc().isMacroID();
}

AST_MATCHER_P(CXXCatchStmt, hasHandler, Matcher<Stmt>, InnerMatcher) {
  Stmt *Handler = Node.getHandlerBlock();
  if (!Handler)
    return false;
  return InnerMatcher.matches(*Handler, Finder, Builder);
}

AST_MATCHER_P(CXXCatchStmt, hasCaughtType, Matcher<QualType>, InnerMatcher) {
  return InnerMatcher.matches(Node.getCaughtType(), Finder, Builder);
}

AST_MATCHER_P(CompoundStmt, hasAnyTextFromList, std::vector<llvm::StringRef>,
              List) {
  if (List.empty())
    return false;

  ASTContext &Context = Finder->getASTContext();
  SourceManager &SM = Context.getSourceManager();
  StringRef Text = Lexer::getSourceText(
      CharSourceRange::getTokenRange(Node.getSourceRange()), SM,
      Context.getLangOpts());
  return std::any_of(List.begin(), List.end(), [&](const StringRef &Str) {
    return Text.contains_insensitive(Str);
  });
}

int Count = 0;
for (auto TI = MI->tokens_begin(), TE = MI->tokens_end(); TI != TE; ++TI) {
  const Token &Tok = *TI;
  if (Tok.isOneOf(tok::l_paren, tok::l_brace, tok::l_square)) {
    ++Count;
  } else if (Tok.isOneOf(tok::r_paren, tok::r_brace, tok::r_square)) {
    --Count;
    if (Count < 0)
      return;
  }
}

SourceLocation Loc;
for (auto TI = MI->tokens_begin(), TE = MI->tokens_end(); TI != TE; ++TI) {
  const Token &Tok = *TI;
  if (Count == 0 && isWarnOp(Tok)) {
    if (TI == MI->tokens_begin() && (TI + 1) != TE && !Tok.isOneOf(tok::plus, tok::minus))
      return;
    if ((TE - 1)->is(tok::star))
      return;
    Loc = Tok.getLocation();
  }
}

if (Loc.isValid()) {
  const Token &Last = *(MI->tokens_end() - 1);
  Check->diag(Loc, "macro replacement list should be enclosed in parentheses")
      << FixItHint::CreateInsertion(MI->tokens_begin()->getLocation(), "(")
      << FixItHint::CreateInsertion(Last.getLocation().getLocWithOffset(
                                        PP->getSpelling(Last).length()),
                                    ")");
}

static bool isKeyword(const Token &T) {
  return T.isOneOf(tok::kw_if, tok::kw_case, tok::kw_const, tok::kw_struct);
}

static bool isWarnOp(const Token &T) {
  return T.isOneOf(tok::plus, tok::minus, tok::star, tok::slash, tok::percent,
                   tok::amp, tok::pipe, tok::caret);
}

static bool possibleVarDecl(const MacroInfo *MI, const Token *Tok) {
  if (Tok == MI->tokens_end())
    return false;

  if (isVarDeclKeyword(*Tok))
    return true;

  if (!Tok->isOneOf(tok::identifier, tok::raw_identifier, tok::coloncolon))
    return false;

  while (Tok != MI->tokens_end() &&
         Tok->isOneOf(tok::identifier, tok::raw_identifier, tok::coloncolon,
                      tok::star, tok::amp, tok::ampamp, tok::less,
                      tok::greater))
    Tok++;

  return Tok == MI->tokens_end() ||
         Tok->isOneOf(tok::equal, tok::semi, tok::l_square, tok::l_paren) ||
         isVarDeclKeyword(*Tok);
}

const auto *Definition = Result.Nodes.getNodeAs<CXXMethodDecl>("x");
if (!Definition)
  return;

if (Definition->isConst()) {
  SourceRange DefConst = getLocationOfConst(Definition->getTypeSourceInfo(),
                                            *Result.SourceManager,
                                            Result.Context->getLangOpts());
  if (DefConst.isInvalid())
    return;

  // ... (further const-handling follows)
}

if (Declaration != Definition) {
  SourceRange DeclConst = getLocationOfConst(Declaration->getTypeSourceInfo(),
                                             *Result.SourceManager,
                                             Result.Context->getLangOpts());
  if (DeclConst.isInvalid())
    return;
  Diag << FixItHint::CreateRemoval(DeclConst);
}

// Then remove 'const' from definition (handled in previous step or next step)

static StringRef getStringFromRange(SourceManager &SourceMgr,
                                    const LangOptions &LangOpts,
                                    SourceRange Range) {
  if (SourceMgr.getFileID(Range.getBegin()) !=
      SourceMgr.getFileID(Range.getEnd()))
    return {};

  return Lexer::getSourceText(CharSourceRange(Range, true), SourceMgr,
                              LangOpts);
}

static SourceRange getLocationOfConst(const TypeSourceInfo *TSI,
                                      SourceManager &SourceMgr,
                                      const LangOptions &LangOpts) {
  assert(TSI);
  const auto FTL = TSI->getTypeLoc().IgnoreParens().getAs<FunctionTypeLoc>();
  assert(FTL);

  SourceRange Range{FTL.getRParenLoc().getLocWithOffset(1),
                    FTL.getLocalRangeEnd()};
  StringRef Text = getStringFromRange(SourceMgr, LangOpts, Range);
  size_t Offset = Text.find("const");
  if (Offset == StringRef::npos)
    return {};

  SourceLocation Start = Range.getBegin().getLocWithOffset(Offset);
  return {Start, Start.getLocWithOffset(strlen("const") - 1)};
}

const SourceManager &SM = *Result.SourceManager;
const LangOptions LangOpts = getLangOpts();
SourceLocation Loc = Result.Nodes.getNodeAs<Stmt>("condStmt")->getBeginLoc();

StringRef AssertMacroName;
while (Loc.isValid() && Loc.isMacroID()) {
  StringRef MacroName = Lexer::getImmediateMacroName(Loc, SM, LangOpts);
  Loc = SM.getImmediateMacroCallerLoc(Loc);

  if (llvm::is_contained(AssertMacros, MacroName)) {
    AssertMacroName = MacroName;
    break;
  }
}

AST_MATCHER_P2(Expr, hasSideEffect, bool, CheckFunctionCalls,
               clang::ast_matchers::internal::Matcher<NamedDecl>,
               IgnoredFunctionsMatcher) {
  const Expr *E = &Node;

  if (const auto *Op = dyn_cast<UnaryOperator>(E)) {
    UnaryOperator::Opcode OC = Op->getOpcode();
    return OC == UO_PostInc || OC == UO_PostDec || OC == UO_PreInc ||
           OC == UO_PreDec;
  }

  if (const auto *Op = dyn_cast<BinaryOperator>(E)) {
    return Op->isAssignmentOp();
  }

  if (const auto *OpCallExpr = dyn_cast<CXXOperatorCallExpr>(E)) {
    OverloadedOperatorKind OpKind = OpCallExpr->getOperator();
    return OpKind == OO_Equal || OpKind == OO_PlusEqual ||
           OpKind == OO_MinusEqual || OpKind == OO_StarEqual ||
           OpKind == OO_SlashEqual || OpKind == OO_AmpEqual ||
           OpKind == OO_PipeEqual || OpKind == OO_CaretEqual ||
           OpKind == OO_LessLessEqual || OpKind == OO_GreaterGreaterEqual ||
           OpKind == OO_PlusPlus || OpKind == OO_MinusMinus ||
           OpKind == OO_PercentEqual || OpKind == OO_New ||
           OpKind == OO_Delete || OpKind == OO_Array_New ||
           OpKind == OO_Array_Delete;
  }

  if (const auto *CExpr = dyn_cast<CallExpr>(E)) {
    bool Result = CheckFunctionCalls;
    if (const auto *FuncDecl = CExpr->getDirectCallee()) {
      if (FuncDecl->getDeclName().isIdentifier() &&
          IgnoredFunctionsMatcher.matches(*FuncDecl, Finder,
                                          Builder))
        Result = false;
      else if (const auto *MethodDecl = dyn_cast<CXXMethodDecl>(FuncDecl))
        Result &= !MethodDecl->isConst();
    }
    return Result;
  }

  return isa<CXXNewExpr>(E) || isa<CXXDeleteExpr>(E) || isa<CXXThrowExpr>(E);
}

const auto *Semicolon = Result.Nodes.getNodeAs<NullStmt>("semi");
SourceLocation LocStart = Semicolon->getBeginLoc();
if (LocStart.isMacroID())
  return;

ASTContext &Ctxt = *Result.Context;
auto Token = utils::lexer::getPreviousToken(LocStart, Ctxt.getSourceManager(),
                                          Ctxt.getLangOpts());
auto &SM = *Result.SourceManager;
unsigned SemicolonLine = SM.getSpellingLineNumber(LocStart);

const auto *Statement = Result.Nodes.getNodeAs<Stmt>("stmt");
const bool IsIfStmt = isa<IfStmt>(Statement);
if (!IsIfStmt &&
    SM.getSpellingLineNumber(Token.getLocation()) != SemicolonLine)
  return;

SourceLocation LocEnd = Semicolon->getEndLoc();
FileID FID = SM.getFileID(LocEnd);
llvm::MemoryBufferRef Buffer = SM.getBufferOrFake(FID, LocEnd);
Lexer Lexer(SM.getLocForStartOfFile(FID), Ctxt.getLangOpts(),
            Buffer.getBufferStart(), SM.getCharacterData(LocEnd) + 1,
            Buffer.getBufferEnd());
if (Lexer.LexFromRawLexer(Token))
  return;

unsigned BaseIndent = SM.getSpellingColumnNumber(Statement->getBeginLoc());
unsigned NewTokenIndent = SM.getSpellingColumnNumber(Token.getLocation());
unsigned NewTokenLine = SM.getSpellingLineNumber(Token.getLocation());
if (!IsIfStmt && NewTokenIndent <= BaseIndent &&
    Token.getKind() != tok::l_brace && NewTokenLine != SemicolonLine)
  return;

void SuspiciousIncludeCheck::registerPPCallbacks(
    const SourceManager &SM, Preprocessor *PP, Preprocessor *ModuleExpanderPP) {
  PP->addPPCallbacks(
      ::std::make_unique<SuspiciousIncludePPCallbacks>(*this, SM, PP));
}

const std::optional<StringRef> IFE =
    utils::getFileExtension(FileName, Check.ImplementationFileExtensions);
if (!IFE)
  return;

for (const auto &HFE : Check.HeaderFileExtensions) {
  SmallString<128> GuessedFileName(FileName);
  llvm::sys::path::replace_extension(GuessedFileName,
                                     (HFE.size() ? "." : "") + HFE);

  OptionalFileEntryRef File =
      PP->LookupFile(DiagLoc, GuessedFileName, IsAngled, nullptr, nullptr,
                     nullptr, nullptr, nullptr, nullptr, nullptr, nullptr);
  if (File) {
    Check.diag(DiagLoc, "did you mean to include '%0'?", DiagnosticIDs::Note)
        << GuessedFileName;
