}

bool FindAssignToVarBefore::isAccessForVar(const Expr *E) const {
  if (const auto *DeclRef = dyn_cast<DeclRefExpr>(E->IgnoreParenCasts()))
    return DeclRef->getDecl() &&
           DeclRef->getDecl()->getCanonicalDecl() == Var &&
           SM.isBeforeInTranslationUnit(E->getBeginLoc(),
                                        VarRef->getBeginLoc());
  return false;
}

const auto *MatchedDecl = Result.Nodes.getNodeAs<CXXMethodDecl>("copyAssignmentOperator");
if (!MatchedDecl)
  return;

if (WarnOnlyIfThisHasSuspiciousField) {
  const auto SmartPointerType = qualType(hasUnqualifiedDesugaredType(
      recordType(hasDeclaration(classTemplateSpecializationDecl(
          hasAnyName("::std::shared_ptr", "::std::unique_ptr",
                     "::std::weak_ptr", "::std::auto_ptr"),
          templateArgumentCountIs(1))))));

  AdditionalMatcher = cxxMethodDecl(ofClass(cxxRecordDecl(
      has(fieldDecl(anyOf(hasType(pointerType()), hasType(SmartPointerType),
                          hasType(arrayType())))))));
}

const auto HasNoSelfCheck = cxxMethodDecl(unless(hasDescendant(
    binaryOperation(hasAnyOperatorName("==", "!="),
                    hasEitherOperand(ignoringParenCasts(cxxThisExpr()))))));

const auto HasNonTemplateSelfCopy = cxxMethodDecl(
    ofClass(cxxRecordDecl(unless(hasAncestor(classTemplateDecl())))),
    traverse(TK_AsIs,
             hasDescendant(cxxConstructExpr(hasDeclaration(cxxConstructorDecl(
                 isCopyConstructor(), ofClass(equalsBoundNode("class"))))))));

const auto HasNoNestedSelfAssign =
    cxxMethodDecl(unless(hasDescendant(cxxMemberCallExpr(callee(cxxMethodDecl(
        hasName("operator="), ofClass(equalsBoundNode("class"))))))));

if (const auto *LessThanZeroOp = Result.Nodes.getNodeAs<BinaryOperator>("ltzop")) {
  SourceLocation OperatorLoc = LessThanZeroOp->getOperatorLoc();
  diag(OperatorLoc, "the comparison always evaluates to false because %0 "
                    "always returns non-negative values")
      << getFunctionSpelling(Result, "ltzop")
      << FixItHint::CreateReplacement(OperatorLoc, Twine(">").str());
  return;
}

if (const auto *AlwaysTrueOp = Result.Nodes.getNodeAs<BinaryOperator>("atop")) {
  diag(AlwaysTrueOp->getOperatorLoc(),
       "the comparison always evaluates to true because %0 always returns "
       "non-negative values")
      << getFunctionSpelling(Result, "atop");
  return;
}

const auto *BinOp = Result.Nodes.getNodeAs<BinaryOperator>("binop");
if (BinOp) {
  diag(BinOp->getOperatorLoc(), "%0 only returns non-negative values")
      << getFunctionSpelling(Result, "binop");
}

static StringRef getFunctionSpelling(const MatchFinder::MatchResult &Result,
                                     const char *BindingStr) {
  const CallExpr *MatchedCall = cast<CallExpr>(
      (Result.Nodes.getNodeAs<BinaryOperator>(BindingStr))->getLHS());
  const SourceManager &SM = *Result.SourceManager;
  return Lexer::getSourceText(CharSourceRange::getTokenRange(
                                  MatchedCall->getCallee()->getSourceRange()),
                              SM, Result.Context->getLangOpts());
}

const auto *InitType = Result.Nodes.getNodeAs<BuiltinType>("InitType");
const auto *IterValueType = Result.Nodes.getNodeAs<BuiltinType>("IterValueType");
const auto *CallNode = Result.Nodes.getNodeAs<CallExpr>("Call");
assert(InitType != nullptr);
assert(IterValueType != nullptr);
assert(CallNode != nullptr);

static bool isValidBuiltinFold(const BuiltinType &ValueType,
                               const BuiltinType &InitType,
                               const ASTContext &Context) {
  const auto ValueTypeSize = Context.getTypeSize(&ValueType);
  const auto InitTypeSize = Context.getTypeSize(&InitType);
  if (ValueType.isFloatingPoint())
    return InitType.isFloatingPoint() && InitTypeSize >= ValueTypeSize;
  if (ValueType.isInteger()) {
    if (InitType.isInteger()) {
      if (InitType.isSignedInteger() == ValueType.isSignedInteger())
        return InitTypeSize >= ValueTypeSize;
      return InitTypeSize > ValueTypeSize;
    }
    if (InitType.isFloatingPoint())
      return InitTypeSize >= ValueTypeSize;
  }
  return false;
}

void FoldInitTypeCheck::doCheck(const BuiltinType &IterValueType,
                                const BuiltinType &InitType,
                                const ASTContext &Context,
                                const CallExpr &CallNode) {
  if (!isValidBuiltinFold(IterValueType, InitType, Context)) {
    diag(CallNode.getExprLoc(), "folding type %0 into type %1 might result in "
                                "loss of precision")
        << IterValueType.desugar() << InitType.desugar();
  }
}

const auto *MatchedDecl = Result.Nodes.getNodeAs<FunctionDecl>("thrower");
if (!MatchedDecl)
  return;

if (Tracer.analyze(MatchedDecl).getBehaviour() ==
    utils::ExceptionAnalyzer::State::Throwing)
  diag(MatchedDecl->getLocation(), "an exception may be thrown in function "
                                   "%0 which should not throw exceptions")
      << MatchedDecl;

AST_MATCHER_P(FunctionDecl, isEnabled, llvm::StringSet<>,
              FunctionsThatShouldNotThrow) {
  return FunctionsThatShouldNotThrow.count(Node.getNameAsString()) > 0;
}

AST_MATCHER(FunctionDecl, isExplicitThrow) {
  return isExplicitThrowExceptionSpec(Node.getExceptionSpecType()) &&
         Node.getExceptionSpecSourceRange().isValid();
}

const auto *Ctor = Result.Nodes.getNodeAs<CXXConstructorDecl>("ctor");
if (!Ctor)
  return;

std::string FixItInitList;
bool HasRelevantBaseInit = false;
bool ShouldNotDoFixit = false;
bool HasWrittenInitializer = false;
SmallVector<FixItHint, 2> SafeFixIts;

for (const auto *Init : Ctor->inits()) {
  bool CtorInitIsWritten = Init->isWritten();
  HasWrittenInitializer = HasWrittenInitializer || CtorInitIsWritten;
  if (!Init->isBaseInitializer())
    continue;

const Type *BaseType = Init->getBaseClass();
if (const auto *TempSpecTy = dyn_cast<TemplateSpecializationType>(BaseType))
  ShouldNotDoFixit = ShouldNotDoFixit || TempSpecTy->isTypeAlias();
ShouldNotDoFixit = ShouldNotDoFixit || isa<TypedefType>(BaseType);
ShouldNotDoFixit = ShouldNotDoFixit || CtorInitIsWritten;

const CXXRecordDecl *BaseClass = BaseType->getAsCXXRecordDecl()->getDefinition();
if (BaseClass->field_empty() &&
    BaseClass->forallBases(
        [](const CXXRecordDecl *Class) { return Class->field_empty(); }))
  continue;

bool NonCopyableBase = false;
for (const auto *Ctor : BaseClass->ctors()) {
  if (Ctor->isCopyConstructor() &&
      (Ctor->getAccess() == AS_private || Ctor->isDeleted())) {
    NonCopyableBase = true;
    break;
  }
}
if (NonCopyableBase)
  continue;

const auto *CExpr = dyn_cast<CXXConstructExpr>(Init->getInit());
if (!CExpr || !CExpr->getConstructor()->isDefaultConstructor())
  continue;
HasRelevantBaseInit = true;

if (CtorInitIsWritten) {
  if (!ParamName.empty())
    SafeFixIts.push_back(
        FixItHint::CreateInsertion(CExpr->getEndLoc(), ParamName));
} else {
  if (Init->getSourceLocation().isMacroID() ||
      Ctor->getLocation().isMacroID() || ShouldNotDoFixit)
    break;
  FixItInitList += BaseClass->getNameAsString();
  FixItInitList += "(" + ParamName + "), ";
}

if (!HasRelevantBaseInit)
  return;

auto Diag = diag(Ctor->getLocation(),
               "calling a base constructor other than the copy constructor")
            << SafeFixIts;

if (FixItInitList.empty() || ParamName.empty() || ShouldNotDoFixit)
  return;

std::string FixItMsg{FixItInitList.substr(0, FixItInitList.size() - 2)};
SourceLocation FixItLoc;
if (!HasWrittenInitializer) {
  FixItLoc = Ctor->getBody()->getBeginLoc();
  FixItMsg = " : " + FixItMsg;
} else {
  FixItLoc = (*Ctor->init_begin())->getSourceLocation();
  FixItMsg += ',';
}
FixItMsg += ' ';

Diag << FixItHint::CreateInsertion(FixItLoc, FixItMsg);

llvm::SmallVector<llvm::Regex> AllowedIdentifiers;
AllowedIdentifiers.reserve(AllowedIdentifiersRaw.size());
for (const auto &Identifier : AllowedIdentifiersRaw) {
  AllowedIdentifiers.emplace_back(Identifier.str());
  if (!AllowedIdentifiers.back().isValid()) {
    configurationDiag("Invalid allowed identifier regex '%0'") << Identifier;
    AllowedIdentifiers.pop_back();
  }
}

static bool hasReservedDoubleUnderscore(StringRef Name, const LangOptions &LangOpts) {
  if (LangOpts.CPlusPlus)
    return Name.contains("__");
  return Name.startswith("__");
}

static std::optional<std::string> getDoubleUnderscoreFixup(StringRef Name, const LangOptions &LangOpts) {
  if (hasReservedDoubleUnderscore(Name, LangOpts))
    return collapseConsecutive(Name, '_');
  return std::nullopt;
}

static bool startsWithUnderscoreCapital(StringRef Name) {
  return Name.size() >= 2 && Name[0] == '_' && std::isupper(Name[1]);
}

static std::optional<std::string> getUnderscoreCapitalFixup(StringRef Name) {
  if (startsWithUnderscoreCapital(Name))
    return std::string(Name.drop_front(1));
  return std::nullopt;
}

static bool startsWithUnderscoreInGlobalNamespace(StringRef Name, bool IsInGlobalNamespace) {
  return IsInGlobalNamespace && Name.size() >= 1 && Name[0] == '_';
}

static std::optional<std::string> getUnderscoreGlobalNamespaceFixup(StringRef Name, bool IsInGlobalNamespace) {
  if (startsWithUnderscoreInGlobalNamespace(Name, IsInGlobalNamespace))
    return std::string(Name.drop_front(1));
  return std::nullopt;
}

static std::string getNonReservedFixup(std::string Name) {
  assert(!Name.empty());
  if (Name[0] == '_' || std::isupper(Name[0]))
    Name.insert(Name.begin(), '_');
  else
    Name.insert(Name.begin(), 2, '_');
  return Name;
}

static std::optional<RenamerClangTidyCheck::FailureInfo> getFailureInfoImpl(StringRef Name, bool IsInGlobalNamespace, const LangOptions &LangOpts, bool Invert, ArrayRef<llvm::Regex> AllowedIdentifiers) {
  if (llvm::any_of(AllowedIdentifiers, [&](const llvm::Regex &Regex) {
        return Regex.match(Name);
      })) {
    return std::nullopt;
  }

  using FailureInfo = RenamerClangTidyCheck::FailureInfo;
  if (!Invert) {
    std::optional<FailureInfo> Info;
    auto AppendFailure = [&](StringRef Kind, std::string &&Fixup) {
      if (!Info) {
        Info = FailureInfo{std::string(Kind), std::move(Fixup)};
      } else {
        Info->KindName += Kind;
        Info->Fixup = std::move(Fixup);
      }
    };
    auto InProgressFixup = [&] {
      return llvm::transformOptional(
                 Info,
                 [](const FailureInfo &Info) { return StringRef(Info.Fixup); })
          .value_or(Name);
    };
    if (auto Fixup = getDoubleUnderscoreFixup(InProgressFixup(), LangOpts))
      AppendFailure(DoubleUnderscoreTag, std::move(*Fixup));
    if (auto Fixup = getUnderscoreCapitalFixup(InProgressFixup()))
      AppendFailure(UnderscoreCapitalTag, std::move(*Fixup));
    if (auto Fixup = getUnderscoreGlobalNamespaceFixup(InProgressFixup(), IsInGlobalNamespace))
      AppendFailure(GlobalUnderscoreTag, std::move(*Fixup));

    return Info;
  }
  if (!(hasReservedDoubleUnderscore(Name, LangOpts) ||
        startsWithUnderscoreCapital(Name) ||
        startsWithUnderscoreInGlobalNamespace(Name, IsInGlobalNamespace)))
    return FailureInfo{NonReservedTag, getNonReservedFixup(std::string(Name))};
  return std::nullopt;
}

static std::string collapseConsecutive(StringRef Str, char C) {
  std::string Result;
  std::unique_copy(Str.begin(), Str.end(), std::back_inserter(Result),
                   [C](char A, char B) { return A == C && B == C; });
  return Result;
}

const auto *E = Result.Nodes.getNodeAs<CXXConstructExpr>("construct");
if (!E)
  return;

AST_MATCHER_P(Stmt, ignoringTemporaryExpr,
              ast_matchers::internal::Matcher<Stmt>, InnerMatcher) {
  const Stmt *E = &Node;
  for (;;) {
    if (const auto *EWC = dyn_cast<ExprWithCleanups>(E))
      E = EWC->getSubExpr();
    else if (const auto *BTE = dyn_cast<CXXBindTemporaryExpr>(E))
      E = BTE->getSubExpr();
    else if (const auto *FCE = dyn_cast<CXXFunctionalCastExpr>(E))
      E = FCE->getSubExpr();
    else
      break;
  }
  return InnerMatcher.matches(*E, Finder, Builder);
}

AST_MATCHER_P(CXXRecordDecl, baseOfBoundNode, std::string, ID) {
  return Builder->removeBindings(
      [&](const ast_matchers::internal::BoundNodesMap &Nodes) {
        const auto *Derived = Nodes.getNodeAs<CXXRecordDecl>(ID);
        return Derived != &Node && !Derived->isDerivedFrom(&Node);
      });
}

const auto PParentStmtExpr = Result.Nodes.getNodeAs<Expr>("stexpr");
const auto ParentCompStmt = Result.Nodes.getNodeAs<CompoundStmt>("parent");
const auto *ParentCond = getCondition(Result.Nodes, "parent");
const auto *ParentReturnStmt = Result.Nodes.getNodeAs<ReturnStmt>("parent");

if (const auto *MemberCall = Result.Nodes.getNodeAs<CXXMemberCallExpr>("empty")) {
  if (ParentCond == MemberCall->getExprStmt())
    return;
  if (PParentStmtExpr && ParentCompStmt && ParentCompStmt->body_back() == MemberCall->getExprStmt())
    return;
  if (ParentReturnStmt)
    return;

ASTContext &Context = MemberCall->getRecordDecl()->getASTContext();
DeclarationName Name = Context.DeclarationNames.getIdentifier(&Context.Idents.get("clear"));

auto Candidates = MemberCall->getRecordDecl()->lookupDependentName(
    Name, [](const NamedDecl *ND) {
      return isa<CXXMethodDecl>(ND) &&
             llvm::cast<CXXMethodDecl>(ND)->getMinRequiredArguments() == 0 &&
             !llvm::cast<CXXMethodDecl>(ND)->isConst();
    });

bool HasClear = !Candidates.empty();

if (HasClear) {
  const CXXMethodDecl *Clear = llvm::cast<CXXMethodDecl>(Candidates.at(0));
  QualType RangeType = MemberCall->getImplicitObjectArgument()->getType();
  bool QualifierIncompatible = (!Clear->isVolatile() && RangeType.isVolatileQualified()) ||
                              RangeType.isConstQualified();
  if (!QualifierIncompatible) {
    diag(MemberLoc, "ignoring the result of 'empty()'; did you mean 'clear()'? ")
        << FixItHint::CreateReplacement(ReplacementRange, "clear");
    return;
  }
}

diag(MemberLoc, "ignoring the result of 'empty()'");

else if (const auto *NonMemberCall = Result.Nodes.getNodeAs<CallExpr>("empty")) {
  if (ParentCond == NonMemberCall->getExprStmt())
    return;
  if (PParentStmtExpr && ParentCompStmt && ParentCompStmt->body_back() == NonMemberCall->getExprStmt())
    return;
  if (ParentReturnStmt)
    return;
  if (NonMemberCall->getNumArgs() != 1)
    return;

const Expr *Arg = NonMemberCall->getArg(0);
CXXRecordDecl *ArgRecordDecl = Arg->getType()->getAsCXXRecordDecl();
if (ArgRecordDecl == nullptr)
  return;

ASTContext &Context = ArgRecordDecl->getASTContext();
DeclarationName Name = Context.DeclarationNames.getIdentifier(&Context.Idents.get("clear"));

auto Candidates = ArgRecordDecl->lookupDependentName(Name, [](const NamedDecl *ND) {
  return isa<CXXMethodDecl>(ND) &&
         llvm::cast<CXXMethodDecl>(ND)->getMinRequiredArguments() == 0 &&
         !llvm::cast<CXXMethodDecl>(ND)->isConst();
});

bool HasClear = !Candidates.empty();

if (HasClear) {
  const CXXMethodDecl *Clear = llvm::cast<CXXMethodDecl>(Candidates.at(0));
  bool QualifierIncompatible = (!Clear->isVolatile() && Arg->getType().isVolatileQualified()) ||
                              Arg->getType().isConstQualified();
  if (!QualifierIncompatible) {
    std::string ReplacementText = std::string(Lexer::getSourceText(
        CharSourceRange::getTokenRange(Arg->getSourceRange()),
        *Result.SourceManager, getLangOpts())) + ".clear()";
    SourceRange ReplacementRange = SourceRange(NonMemberLoc, NonMemberEndLoc);
    diag(NonMemberLoc, "ignoring the result of '%0'; did you mean 'clear()'?")
        << llvm::dyn_cast<NamedDecl>(NonMemberCall->getCalleeDecl())->getQualifiedNameAsString()
        << FixItHint::CreateReplacement(ReplacementRange, ReplacementText);
    return;
  }
}

diag(NonMemberLoc, "ignoring the result of '%0'")
    << llvm::dyn_cast<NamedDecl>(NonMemberCall->getCalleeDecl())->getQualifiedNameAsString();

const Expr *getCondition(const BoundNodes &Nodes, const StringRef NodeId) {
  const auto *If = Nodes.getNodeAs<IfStmt>(NodeId);
  if (If != nullptr)
    return If->getCond();

  const auto *For = Nodes.getNodeAs<ForStmt>(NodeId);
  if (For != nullptr)
    return For->getCond();

  const auto *While = Nodes.getNodeAs<WhileStmt>(NodeId);
  if (While != nullptr)
    return While->getCond();

  const auto *Do = Nodes.getNodeAs<DoStmt>(NodeId);
  if (Do != nullptr)
    return Do->getCond();

  const auto *Switch = Nodes.getNodeAs<SwitchStmt>(NodeId);
  if (Switch != nullptr)
    return Switch->getCond();

  return nullptr;
}

const Expr *SizeExpr = CE->getArg(2);
assert(SizeExpr != nullptr && "Third argument of memcmp is mandatory.");
std::optional<uint64_t> ComparedBits = tryEvaluateSizeExpr(SizeExpr, Ctx);

static std::optional<uint64_t> tryEvaluateSizeExpr(const Expr *SizeExpr,
                                                   const ASTContext &Ctx) {
  Expr::EvalResult Result;
  if (SizeExpr->EvaluateAsRValue(Result, Ctx))
    return Ctx.toBits(
        CharUnits::fromQuantity(Result.Val.getInt().getExtValue()));
  return std::nullopt;
}

for (unsigned int ArgIndex = 0; ArgIndex < 2; ++ArgIndex) {
  const Expr *ArgExpr = CE->getArg(ArgIndex);
  QualType ArgType = ArgExpr->IgnoreImplicit()->getType();
  const Type *PointeeType = ArgType->getPointeeOrArrayElementType();
  assert(PointeeType != nullptr && "PointeeType should always be available.");
  QualType PointeeQualifiedType(PointeeType, 0);

if (PointeeType->isRecordType()) {
  if (const RecordDecl *RD =
          PointeeType->getAsRecordDecl()->getDefinition()) {
    if (const auto *CXXDecl = dyn_cast<CXXRecordDecl>(RD)) {
      if (!CXXDecl->isStandardLayout()) {
        diag(CE->getBeginLoc(),
             "comparing object representation of non-standard-layout type "
             "%0; consider using a comparison operator instead")
            << PointeeQualifiedType;
        break;
      }
    }
  }
}

if (!PointeeType->isIncompleteType()) {
  uint64_t PointeeSize = Ctx.getTypeSize(PointeeType);
  if (ComparedBits && *ComparedBits >= PointeeSize &&
      !Ctx.hasUniqueObjectRepresentations(PointeeQualifiedType)) {
    diag(CE->getBeginLoc(),
         "comparing object representation of type %0 which does not have a "
         "unique object representation; consider comparing %select{the "
         "values|the members of the object}1 manually")
        << PointeeQualifiedType << (PointeeType->isRecordType() ? 1 : 0);
    break;
  }
}

