void AssignmentInIfConditionCheck::report(const Expr *AssignmentExpr) {
  SourceLocation OpLoc =
      isa<BinaryOperator>(AssignmentExpr)
          ? cast<BinaryOperator>(AssignmentExpr)->getOperatorLoc()
          : cast<CXXOperatorCallExpr>(AssignmentExpr)->getOperatorLoc();

  diag(OpLoc, "an assignment within an 'if' condition is bug-prone")
      << AssignmentExpr->getSourceRange();
  diag(OpLoc,
       "if it should be an assignment, move it out of the 'if' condition",
       DiagnosticIDs::Note);
  diag(OpLoc, "if it is meant to be an equality check, change '=' to '=='",
       DiagnosticIDs::Note);
}

const auto *OuterIf = Result.Nodes.getNodeAs<IfStmt>(OuterIfStr);
const auto *InnerIf = Result.Nodes.getNodeAs<IfStmt>(InnerIfStr);
const auto *CondVar = Result.Nodes.getNodeAs<VarDecl>(CondVarStr);
const auto *Func = Result.Nodes.getNodeAs<FunctionDecl>(FuncStr);

const DeclRefExpr *OuterIfVar, *InnerIfVar;
if (const auto *Inner = Result.Nodes.getNodeAs<DeclRefExpr>(InnerIfVar1Str))
  InnerIfVar = Inner;
else
  InnerIfVar = Result.Nodes.getNodeAs<DeclRefExpr>(InnerIfVar2Str);
if (const auto *Outer = Result.Nodes.getNodeAs<DeclRefExpr>(OuterIfVar1Str))
  OuterIfVar = Outer;
else
  OuterIfVar = Result.Nodes.getNodeAs<DeclRefExpr>(OuterIfVar2Str);

if (OuterIfVar && InnerIfVar) {
  if (isChangedBefore(OuterIf->getThen(), InnerIfVar, OuterIfVar, CondVar,
                      Result.Context))
    return;

  if (isChangedBefore(OuterIf->getCond(), InnerIfVar, OuterIfVar, CondVar,
                      Result.Context))
    return;
}

auto Diag = diag(InnerIf->getBeginLoc(), "redundant condition %0") << CondVar;

const auto *BinOpCond =
    dyn_cast<BinaryOperator>(InnerIf->getCond()->IgnoreParenImpCasts());

if (isa<DeclRefExpr>(InnerIf->getCond()->IgnoreParenImpCasts()) ||
    (BinOpCond && BinOpCond->getOpcode() == BO_LOr)) {
  // Handle simple DeclRefExpr or OR conditions
  SourceLocation IfBegin = InnerIf->getBeginLoc();
  const Stmt *Body = InnerIf->getThen();
  const Expr *OtherSide = nullptr;
  if (BinOpCond) {
    const auto *LeftDRE =
        dyn_cast<DeclRefExpr>(BinOpCond->getLHS()->IgnoreParenImpCasts());
    if (LeftDRE && LeftDRE->getDecl() == CondVar)
      OtherSide = BinOpCond->getRHS();
    else
      OtherSide = BinOpCond->getLHS();
  }

  SourceLocation IfEnd = Body->getBeginLoc().getLocWithOffset(-1);

  if (isa<CompoundStmt>(Body))
    IfEnd = Body->getBeginLoc();

  if (OtherSide && OtherSide->HasSideEffects(*Result.Context)) {
    SourceLocation BeforeOtherSide =
        OtherSide->getBeginLoc().getLocWithOffset(-1);
    SourceLocation AfterOtherSide =
        Lexer::findNextToken(OtherSide->getEndLoc(), *Result.SourceManager,
                             getLangOpts())
            ->getLocation();
    Diag << FixItHint::CreateRemoval(
                CharSourceRange::getTokenRange(IfBegin, BeforeOtherSide))
         << FixItHint::CreateInsertion(AfterOtherSide, ";")
         << FixItHint::CreateRemoval(
                CharSourceRange::getTokenRange(AfterOtherSide, IfEnd));
  } else {
    Diag << FixItHint::CreateRemoval(
        CharSourceRange::getTokenRange(IfBegin, IfEnd));
  }

  if (isa<CompoundStmt>(Body))
    Diag << FixItHint::CreateRemoval(
        CharSourceRange::getTokenRange(Body->getEndLoc(), Body->getEndLoc()));
} else {
  // Handle AND conditions
  const auto *CondOp =
      cast<BinaryOperator>(InnerIf->getCond()->IgnoreParenImpCasts());
  const auto *LeftDRE =
      dyn_cast<DeclRefExpr>(CondOp->getLHS()->IgnoreParenImpCasts());
  if (LeftDRE && LeftDRE->getDecl() == CondVar) {
    SourceLocation BeforeRHS =
        CondOp->getRHS()->getBeginLoc().getLocWithOffset(-1);
    Diag << FixItHint::CreateRemoval(CharSourceRange::getTokenRange(
        CondOp->getLHS()->getBeginLoc(), BeforeRHS));
  } else {
    SourceLocation AfterLHS =
        Lexer::findNextToken(CondOp->getLHS()->getEndLoc(),
                             *Result.SourceManager, getLangOpts())
            ->getLocation();
    Diag << FixItHint::CreateRemoval(CharSourceRange::getTokenRange(
        AfterLHS, CondOp->getRHS()->getEndLoc()));
  }
}

static bool isChangedBefore(const Stmt *S, const Stmt *NextS, const Stmt *PrevS,
                          const VarDecl *Var, ASTContext *Context) {
  ExprMutationAnalyzer MutAn(*S, *Context);
  const auto &SM = Context->getSourceManager();
  const Stmt *MutS = MutAn.findMutation(Var);
  return MutS &&
         SM.isBeforeInTranslationUnit(PrevS->getEndLoc(),
                                      MutS->getBeginLoc()) &&
         SM.isBeforeInTranslationUnit(MutS->getEndLoc(), NextS->getBeginLoc());
}

const auto *Matched = Result.Nodes.getNodeAs<CallExpr>("match");
if (!Matched)
  return;

diag(Matched->getBeginLoc(),
     "the value returned by this function should be used")
    << Matched->getSourceRange();

diag(Matched->getBeginLoc(),
     "cast the expression to void to silence this warning",
     DiagnosticIDs::Note);

AST_MATCHER_P(FunctionDecl, isInstantiatedFrom, Matcher<FunctionDecl>,
              InnerMatcher) {
  FunctionDecl *InstantiatedFrom = Node.getInstantiatedFromMemberFunction();
  return InnerMatcher.matches(InstantiatedFrom ? *InstantiatedFrom : Node,
                              Finder, Builder);
}

if (!isa<IfStmt>(Else)) {
  if (utils::areStatementsIdentical(Then->IgnoreContainers(),
                                Else->IgnoreContainers(), Context)) {
    diag(IS->getBeginLoc(), "if with identical then and else branches");
    diag(IS->getElseLoc(), "else branch starts here", DiagnosticIDs::Note);
  }
  return;
}

llvm::SmallVector<const Stmt *, 4> Branches;
const IfStmt *Cur = IS;
while (true) {
  Branches.push_back(Cur->getThen());
  Else = Cur->getElse();
  if (!Else)
    break;
  Cur = dyn_cast<IfStmt>(Else);
  if (!Cur) {
    Branches.push_back(Else);
    break;
  }
}

size_t N = Branches.size();
llvm::BitVector KnownAsClone(N);
for (size_t I = 0; I + 1 < N; I++) {
  if (KnownAsClone[I])
    continue;
  int NumCopies = 1;
  for (size_t J = I + 1; J < N; J++) {
    if (KnownAsClone[J] || !utils::areStatementsIdentical(
                               Branches[I]->IgnoreContainers(),
                               Branches[J]->IgnoreContainers(), Context))
      continue;
    NumCopies++;
    KnownAsClone[J] = true;
    if (NumCopies == 2) {
      diag(Branches[I]->getBeginLoc(),
           "repeated branch body in conditional chain");
      SourceLocation End =
          Lexer::getLocForEndOfToken(Branches[I]->getEndLoc(), 0,
                                   *Result.SourceManager, getLangOpts());
      if (End.isValid()) {
        diag(End, "end of the original", DiagnosticIDs::Note);
      }
    }
    diag(Branches[J]->getBeginLoc(), "clone %0 starts here",
         DiagnosticIDs::Note)
        << (NumCopies - 1);
  }
}

if (const auto *CO = Result.Nodes.getNodeAs<ConditionalOperator>("condOp")) {
  if (utils::areStatementsIdentical(CO->getTrueExpr(), CO->getFalseExpr(),
                                    Context))
    diag(CO->getQuestionLoc(),
         "conditional operator with identical true and false expressions");
  return;
}

llvm::SmallVector<SwitchBranch, 4> Branches;
for (const Stmt *S : Body->body()) {
  if (isa<SwitchCase>(S))
    Branches.emplace_back();
  if (!Branches.empty())
    Branches.back().push_back(S);
}

auto *End = Branches.end();
auto *BeginCurrent = Branches.begin();
while (BeginCurrent < End) {
  if (isFallthroughSwitchBranch(*BeginCurrent)) {
    ++BeginCurrent;
    continue;
  }
  auto *EndCurrent = BeginCurrent + 1;
  while (EndCurrent < End &&
         areSwitchBranchesIdentical(*BeginCurrent, *EndCurrent, Context)) {
    ++EndCurrent;
  }
  if (EndCurrent == (BeginCurrent + 1)) {
    BeginCurrent = EndCurrent;
    continue;
  }
  diag(BeginCurrent->front()->getBeginLoc(),
       "switch has %0 consecutive identical branches")
      << static_cast<int>(std::distance(BeginCurrent, EndCurrent));
  SourceLocation EndLoc = (EndCurrent - 1)->back()->getEndLoc();
  if (EndLoc.isInvalid())
    EndLoc = (EndCurrent - 1)->back()->getBeginLoc();
  if (EndLoc.isMacroID())
    EndLoc = Context.getSourceManager().getExpansionLoc(EndLoc);
  EndLoc = Lexer::getLocForEndOfToken(EndLoc, 0, *Result.SourceManager,
                                    getLangOpts());
  if (EndLoc.isValid()) {
    diag(EndLoc, "last of these clones ends here", DiagnosticIDs::Note);
  }
  BeginCurrent = EndCurrent;
}

const auto *MatchedWait = Result.Nodes.getNodeAs<CallExpr>("wait");
if (!MatchedWait)
  return;

const auto *E = Result.Nodes.getNodeAs<Expr>("expr");
if (!E)
  return;

const CallExpr *Call = dyn_cast<CallExpr>(E);
const CXXConstructExpr *Construct = dyn_cast<CXXConstructExpr>(E);

if (Call) {
  const FunctionDecl *Callee = Call->getDirectCallee();
  if (!Callee)
    return;

  checkCallArgs(Result.Context, Callee, Call->getCallee()->getEndLoc(),
                llvm::ArrayRef(Call->getArgs(), Call->getNumArgs()));
}

if (Construct) {
  if (Construct->getNumArgs() > 0 &&
      Construct->getArg(0)->getSourceRange() == Construct->getSourceRange()) {
    return;
  }
  checkCallArgs(Result.Context, Construct->getConstructor(),
                Construct->getParenOrBraceRange().getBegin(),
                llvm::ArrayRef(Construct->getArgs(), Construct->getNumArgs()));
}

static const FunctionDecl *resolveMocks(const FunctionDecl *Func) {
  if (const auto *Method = dyn_cast<CXXMethodDecl>(Func)) {
    if (const auto *MockedMethod = findMockedMethod(Method)) {
      if (MockedMethod->size_overridden_methods() > 0) {
        return *MockedMethod->begin_overridden_methods();
      }
      return nullptr;
    }
  }
  return Func;
}

bool ArgumentCommentCheck::shouldAddComment(const Expr *Arg) const {
  Arg = Arg->IgnoreImpCasts();
  if (isa<UnaryOperator>(Arg))
    Arg = cast<UnaryOperator>(Arg)->getSubExpr();
  if (Arg->getExprLoc().isMacroID())
    return false;
  return (CommentBoolLiterals && isa<CXXBoolLiteralExpr>(Arg)) ||
         (CommentIntegerLiterals && isa<IntegerLiteral>(Arg)) ||
         (CommentFloatLiterals && isa<FloatingLiteral>(Arg)) ||
         (CommentUserDefinedLiterals && isa<UserDefinedLiteral>(Arg)) ||
         (CommentCharacterLiterals && isa<CharacterLiteral>(Arg)) ||
         (CommentStringLiterals && isa<StringLiteral>(Arg)) ||
         (CommentNullPtrs && isa<CXXNullPtrLiteralExpr>(Arg));
}

