}

static std::vector<std::pair<SourceLocation, StringRef>>
getCommentsInRange(ASTContext *Ctx, CharSourceRange Range) {
  std::vector<std::pair<SourceLocation, StringRef>> Comments;
  auto &SM = Ctx->getSourceManager();
  std::pair<FileID, unsigned> BeginLoc = SM.getDecomposedLoc(Range.getBegin()),
                              EndLoc = SM.getDecomposedLoc(Range.getEnd());

  if (BeginLoc.first != EndLoc.first)
    return Comments;

  bool Invalid = false;
  StringRef Buffer = SM.getBufferData(BeginLoc.first, &Invalid);
  if (Invalid)
    return Comments;

  const char *StrData = Buffer.data() + BeginLoc.second;

  Lexer TheLexer(SM.getLocForStartOfFile(BeginLoc.first), Ctx->getLangOpts(),
                 Buffer.begin(), StrData, Buffer.end());
  TheLexer.SetCommentRetentionState(true);

  while (true) {
    Token Tok;
    if (TheLexer.LexFromRawLexer(Tok))
      break;
    if (Tok.getLocation() == Range.getEnd() || Tok.is(tok::eof))
      break;

    if (Tok.is(tok::comment)) {
      std::pair<FileID, unsigned> CommentLoc =
          SM.getDecomposedLoc(Tok.getLocation());
      assert(CommentLoc.first == BeginLoc.first);
      Comments.emplace_back(
          Tok.getLocation(),
          StringRef(Buffer.begin() + CommentLoc.second, Tok.getLength()));
    } else {
      Comments.clear();
    }
  }

  return Comments;
}

const auto *MatchedExpr = Result.Nodes.getNodeAs<CXXNewExpr>("new-expr");
if (!MatchedExpr)
  return;

AST_MATCHER_P(CXXTryStmt, hasHandlerFor,
              ast_matchers::internal::Matcher<QualType>, InnerMatcher) {
  for (unsigned NH = Node.getNumHandlers(), I = 0; I < NH; ++I) {
    const CXXCatchStmt *CatchS = Node.getHandler(I);
    if (CatchS->getCaughtType().isNull())
      return true;
    ast_matchers::internal::BoundNodesTreeBuilder Result(*Builder);
    if (InnerMatcher.matches(CatchS->getCaughtType(), Finder, &Result)) {
      *Builder = std::move(Result);
      return true;
    }
  }
  return false;
}

AST_MATCHER(CXXNewExpr, mayThrow) {
  FunctionDecl *OperatorNew = Node.getOperatorNew();
  if (!OperatorNew)
    return false;
  return !OperatorNew->getType()->castAs<FunctionProtoType>()->isNothrow();
}

AST_MATCHER_P(InitListExpr, initCountIs, unsigned, N) {
  return Node.getNumInits() == N;
}

AST_MATCHER(clang::VarDecl, isDirectInitialization) {
  return Node.getInitStyle() != clang::VarDecl::InitializationStyle::CInit;
}

auto NullLiteral = implicitCastExpr(
    hasCastKind(clang::CK_NullToPointer),
    hasSourceExpression(ignoringParens(cxxNullPtrLiteralExpr())));

if (const auto *Call = Result.Nodes.getNodeAs<CallExpr>("dest")) {
  QualType DestType = Call->getArg(0)->IgnoreImplicit()->getType();
  if (!DestType->getPointeeType().isNull())
    DestType = DestType->getPointeeType();
  diag(Call->getBeginLoc(), "undefined behavior, destination object type %0 "
                            "is not TriviallyCopyable")
      << DestType;
}

if (const auto *Call = Result.Nodes.getNodeAs<CallExpr>("src")) {
  QualType SourceType = Call->getArg(1)->IgnoreImplicit()->getType();
  if (!SourceType->getPointeeType().isNull())
    SourceType = SourceType->getPointeeType();
  diag(Call->getBeginLoc(),
       "undefined behavior, source object type %0 is not TriviallyCopyable")
      << SourceType;
}

AST_MATCHER(CXXRecordDecl, isNotTriviallyCopyable) {
  return Node.hasDefinition() ? !Node.isTriviallyCopyable() : false;
}

const auto *Decl = Result.Nodes.getNodeAs<FunctionDecl>("decl");
const auto *Call = Result.Nodes.getNodeAs<CallExpr>("call");
assert(Decl != nullptr && Call != nullptr);

if (Result.Nodes.getNodeAs<Stmt>("missing-comparison")) {
  SourceLocation EndLoc = Lexer::getLocForEndOfToken(
      Call->getRParenLoc(), 0, Result.Context->getSourceManager(),
      getLangOpts());

  diag(Call->getBeginLoc(),
       "function %0 is called without explicitly comparing result")
      << Decl << FixItHint::CreateInsertion(EndLoc, " != 0");
}

if (const auto *E = Result.Nodes.getNodeAs<Expr>("logical-not-comparison")) {
  SourceLocation EndLoc = Lexer::getLocForEndOfToken(
      Call->getRParenLoc(), 0, Result.Context->getSourceManager(),
      getLangOpts());
  SourceLocation NotLoc = E->getBeginLoc();

  diag(Call->getBeginLoc(),
       "function %0 is compared using logical not operator")
      << Decl
      << FixItHint::CreateRemoval(
             CharSourceRange::getTokenRange(NotLoc, NotLoc))
      << FixItHint::CreateInsertion(EndLoc, " == 0");
}

if (Result.Nodes.getNodeAs<Stmt>("invalid-comparison")) {
  diag(Call->getBeginLoc(),
       "function %0 is compared to a suspicious constant")
      << Decl;
}

if (const auto *BinOp =
        Result.Nodes.getNodeAs<BinaryOperator>("suspicious-operator")) {
  diag(Call->getBeginLoc(), "results of function %0 used by operator '%1'")
      << Decl << BinOp->getOpcodeStr();
}

if (Result.Nodes.getNodeAs<Stmt>("invalid-conversion")) {
  diag(Call->getBeginLoc(), "function %0 has suspicious implicit cast")
      << Decl;
}

if (const auto *CharZeroFill = Result.Nodes.getNodeAs<CharacterLiteral>("char-zero-fill")) {
  SourceRange CharRange = CharZeroFill->getSourceRange();
  auto Diag = diag(CharZeroFill->getBeginLoc(), "memset fill value is char '0', potentially mistaken for int 0");
  if (!CharRange.getBegin().isMacroID())
    Diag << FixItHint::CreateReplacement(CharSourceRange::getTokenRange(CharRange), "0");
}

else if (const auto *NumFill = Result.Nodes.getNodeAs<IntegerLiteral>("num-fill")) {
  const auto UCharMax = (1 << Result.Context->getCharWidth()) - 1;
  Expr::EvalResult EVResult;
  if (NumFill->EvaluateAsInt(EVResult, *Result.Context)) {
    llvm::APSInt NumValue = EVResult.Val.getInt();
    if (NumValue < 0 || NumValue > UCharMax)
      diag(NumFill->getBeginLoc(), "memset fill value is out of unsigned character range, gets truncated");
  }
}

else if (const auto *Call = Result.Nodes.getNodeAs<CallExpr>("call")) {
  const Expr *FillChar = Call->getArg(1);
  const Expr *ByteCount = Call->getArg(2);
  Expr::EvalResult Value2;
  if (!ByteCount->isValueDependent() &&
      ByteCount->EvaluateAsInt(Value2, *Result.Context) &&
      Value2.Val.getInt() == 0) {
    Expr::EvalResult EVResult;
    if (FillChar->isValueDependent() ||
        !FillChar->EvaluateAsInt(EVResult, *Result.Context) ||
        (EVResult.Val.getInt() != 0 && !EVResult.Val.getInt().isNegative())) {
      auto D = diag(Call->getBeginLoc(), "memset of size zero, potentially swapped arguments");
      StringRef RHSString = tooling::fixit::getText(*ByteCount, *Result.Context);
      StringRef LHSString = tooling::fixit::getText(*FillChar, *Result.Context);
      if (!LHSString.empty() && !RHSString.empty()) {
        D << tooling::fixit::createReplacement(*FillChar, RHSString)
          << tooling::fixit::createReplacement(*ByteCount, LHSString);
      }
    }
  }
}

static bool isKnownZero(const Expr *E, ASTContext *Context) {
  Expr::EvalResult Result;
  return !E->isValueDependent() &&
         E->EvaluateAsInt(Result, *Context) &&
         Result.Val.getInt() == 0;
}

static bool isKnownPositive(const Expr *E, ASTContext *Context) {
  Expr::EvalResult Result;
  return !E->isValueDependent() &&
         E->EvaluateAsInt(Result, *Context) &&
         Result.Val.getInt() > 0;
}

const ASTContext &Ctx = *Result.Context;
const auto *Call = Result.Nodes.getNodeAs<CallExpr>("call");
if (!Call)
  return;

for (unsigned I = 1, E = Call->getNumArgs(); I < E; ++I) {
  const Expr *LHS = Call->getArg(I - 1);
  const Expr *RHS = Call->getArg(I);

  if (UsedArgs.count(RHS))
    continue;

const auto *LHSCast = dyn_cast<ImplicitCastExpr>(ignoreNoOpCasts(LHS));
const auto *RHSCast = dyn_cast<ImplicitCastExpr>(ignoreNoOpCasts(RHS));

if (!LHSCast || !RHSCast || !isImplicitCastCandidate(LHSCast) ||
    !isImplicitCastCandidate(RHSCast))
  continue;

if (!areArgumentsPotentiallySwapped(LHS->getType(), RHS->getType(),
                                  LHSFrom->getType(), RHSFrom->getType()))
  continue;

static const Expr *ignoreNoOpCasts(const Expr *E) {
  if (auto *Cast = dyn_cast<CastExpr>(E))
    if (Cast->getCastKind() == CK_LValueToRValue ||
        Cast->getCastKind() == CK_NoOp)
      return ignoreNoOpCasts(Cast->getSubExpr());
  return E;
}

static bool areTypesSemiEqual(const QualType L, const QualType R) {
  if (L == R)
    return true;

  if (!L->isBuiltinType() || !R->isBuiltinType())
    return false;

  return (L->isFloatingType() && R->isFloatingType()) ||
         (L->isIntegerType() && R->isIntegerType()) ||
         (L->isBooleanType() && R->isBooleanType());
}

static bool areArgumentsPotentiallySwapped(const QualType LTo,
                                         const QualType RTo,
                                         const QualType LFrom,
                                         const QualType RFrom) {
  if (LTo == RTo || LFrom == RFrom)
    return false;

  const bool REq = areTypesSemiEqual(RTo, LFrom);
  if (LTo == RFrom && REq)
    return true;

  bool LEq = areTypesSemiEqual(LTo, RFrom);
  if (RTo == LFrom && LEq)
    return true;

  if (REq && LEq && !areTypesSemiEqual(RTo, LTo))
    return true;

  return false;
}

const auto *E = Result.Nodes.getNodeAs<CXXConstructExpr>("constructor");
assert(E && "missing constructor expression");
SourceLocation Loc = E->getBeginLoc();

if (Result.Nodes.getNodeAs<Expr>("swapped-parameter")) {
  const Expr *P0 = E->getArg(0);
  const Expr *P1 = E->getArg(1);
  diag(Loc, "string constructor parameters are probably swapped;"
            " expecting string(count, character)")
      << tooling::fixit::createReplacement(*P0, *P1, Ctx)
      << tooling::fixit::createReplacement(*P1, *P0, Ctx);
}

else if (Result.Nodes.getNodeAs<Expr>("empty-string")) {
  diag(Loc, "constructor creating an empty string");
}

else if (Result.Nodes.getNodeAs<Expr>("negative-length")) {
  diag(Loc, "negative value used as length parameter");
}

else if (Result.Nodes.getNodeAs<Expr>("large-length")) {
  if (WarnOnLargeLength)
    diag(Loc, "suspicious large length parameter");
}

else if (Result.Nodes.getNodeAs<Expr>("literal-with-length")) {
  const auto *Str = Result.Nodes.getNodeAs<StringLiteral>("str");
  const auto *Lit = Result.Nodes.getNodeAs<IntegerLiteral>("int");
  if (Lit->getValue().ugt(Str->getLength())) {
    diag(Loc, "length is bigger than string literal size");
  }
}

else if (const auto *Ptr = Result.Nodes.getNodeAs<Expr>("from-ptr")) {
  Expr::EvalResult ConstPtr;
  if (!Ptr->isInstantiationDependent() &&
      Ptr->EvaluateAsRValue(ConstPtr, Ctx) &&
      ((ConstPtr.Val.isInt() && ConstPtr.Val.getInt().isZero()) ||
       (ConstPtr.Val.isLValue() && ConstPtr.Val.isNullPointer()))) {
    if (IsStringviewNullptrCheckEnabled &&
        Result.Nodes.getNodeAs<CXXRecordDecl>("basic_string_view_decl")) {
      return;
    }
    diag(Loc, "constructing string from nullptr is undefined behaviour");
  }
}

static std::vector<StringRef>
removeNamespaces(const std::vector<StringRef> &Names) {
  std::vector<StringRef> Result;
  Result.reserve(Names.size());
  for (StringRef Name : Names) {
    std::string::size_type ColonPos = Name.rfind(':');
    Result.push_back(
        Name.substr(ColonPos == std::string::npos ? 0 : ColonPos + 1));
  }
  return Result;
}

return classTemplateSpecializationDecl(
    hasName("::std::unique_ptr"), templateArgumentCountIs(2),
    hasTemplateArgument(
        0, templateArgument(refersToType(qualType().bind(PointerTypeN)))),
    hasTemplateArgument(1, templateArgument(refersToType(
                               qualType(hasDeclaration(DeleterDecl))))));

UniquePtrArrayMismatchCheck::UniquePtrArrayMismatchCheck(
    StringRef Name, ClangTidyContext *Context)
    : SmartPtrArrayMismatchCheck(Name, Context, "unique") {}

const auto *Argument = Result.Nodes.getNodeAs<Expr>("expr");
const auto CharType =
    Result.Nodes.getNodeAs<QualType>("type")->getCanonicalType();
SourceLocation Loc = Argument->getBeginLoc();

if (CharExpressionDetector(CharType, *Result.Context)
        .isLikelyCharExpression(Argument))
  return;

if (Loc.isMacroID())
  return;

bool IsWideCharType = CharType->isWideCharType();
if (!CharType->isCharType() && !IsWideCharType)
  return;

bool IsOneDigit = false;
bool IsLiteral = false;
if (const auto *Literal = dyn_cast<IntegerLiteral>(Argument)) {
  IsOneDigit = Literal->getValue().getLimitedValue() < 10;
  IsLiteral = true;
}

if (IsOneDigit) {
  Diag << FixItHint::CreateInsertion(Loc, IsWideCharType ? "L'" : "'")
       << FixItHint::CreateInsertion(EndLoc, "'");
  return;
}

if (IsLiteral) {
  Diag << FixItHint::CreateInsertion(Loc, IsWideCharType ? "L\"" : "\"")
       << FixItHint::CreateInsertion(EndLoc, "\"");
  return;
}

if (getLangOpts().CPlusPlus11) {
  Diag << FixItHint::CreateInsertion(Loc, IsWideCharType ? "std::to_wstring("
                                                       : "std::to_string(")
       << FixItHint::CreateInsertion(EndLoc, ")");
}

bool CharExpressionDetector::isLikelyCharExpression(const Expr *E) const {
  if (isCharTyped(E))
    return true;

  if (const auto *BinOp = dyn_cast<BinaryOperator>(E)) {
    const auto *LHS = BinOp->getLHS()->IgnoreParenImpCasts();
    const auto *RHS = BinOp->getRHS()->IgnoreParenImpCasts();
    if (BinOp->isAdditiveOp() || BinOp->isBitwiseOp())
      return handleBinaryOp(BinOp->getOpcode(), LHS, RHS) ||
             handleBinaryOp(BinOp->getOpcode(), RHS, LHS);
    if (BinOp->getOpcode() == BO_Rem)
      return handleBinaryOp(BinOp->getOpcode(), LHS, RHS);
    return false;
  }

  if (const auto *CondOp = dyn_cast<AbstractConditionalOperator>(E))
    return isLikelyCharExpression(
               CondOp->getFalseExpr()->IgnoreParenImpCasts()) ||
           isLikelyCharExpression(
               CondOp->getTrueExpr()->IgnoreParenImpCasts());
  return false;
}

bool CharExpressionDetector::handleBinaryOp(clang::BinaryOperatorKind Opcode, const Expr *const LHS,
                    const Expr *const RHS) const {
  if (isCharTyped(LHS) && isCharTyped(RHS))
    return true;

  if ((Opcode == BO_And || Opcode == BO_Rem) && isCharValuedConstant(RHS))
    return true;

  if (Opcode == BO_Or && isCharTyped(LHS) && isCharValuedConstant(RHS))
    return true;

  if (Opcode == BO_Add)
    return isCharConstant(LHS) && isLikelyCharExpression(RHS);

  return false;
}

bool CharExpressionDetector::isCharConstant(const Expr *E) const {
  return isCharTyped(E) && isCharValuedConstant(E);
};

bool CharExpressionDetector::isCharValuedConstant(const Expr *E) const {
  if (E->isInstantiationDependent())
    return false;
  Expr::EvalResult EvalResult;
  if (!E->EvaluateAsInt(EvalResult, Ctx, Expr::SE_AllowSideEffects))
    return false;
  return EvalResult.Val.getInt().getActiveBits() <= Ctx.getTypeSize(CharType);
};

bool CharExpressionDetector::isCharTyped(const Expr *E) const {
  return E->getType().getCanonicalType().getTypePtr() ==
         CharType.getTypePtr();
};

const auto *MatchedEscapingBlock = Result.Nodes.getNodeAs<BlockExpr>("arg-block");
if (!MatchedEscapingBlock)
  return;

for (const BlockDecl::Capture &CapturedVar : EscapingBlockDecl->captures()) {
  const VarDecl *Var = CapturedVar.getVariable();
  if (Var && Var->hasAttr<NoEscapeAttr>()) {
    // ... (diagnostic logic follows)
  }
}

if (Var && Var->hasAttr<NoEscapeAttr>()) {
  diag(MatchedEscapingBlock->getBeginLoc(),
       "pointer %0 with attribute 'noescape' is captured by an "
       "asynchronously-executed block")
      << Var;
  diag(Var->getBeginLoc(), "the 'noescape' attribute is declared here.",
       DiagnosticIDs::Note);
}

if (const auto *HandlerLambda = Result.Nodes.getNodeAs<LambdaExpr>("handler_lambda")) {
  diag(HandlerLambda->getBeginLoc(),
       "lambda function is not allowed as signal handler (until C++17)")
      << HandlerLambda->getSourceRange();
  return;
}

const auto *HandlerDecl = Result.Nodes.getNodeAs<FunctionDecl>("handler_decl");
const auto *HandlerExpr = Result.Nodes.getNodeAs<DeclRefExpr>("handler_expr");
assert(Result.Nodes.getNodeAs<CallExpr>("register_call") && HandlerDecl &&
       HandlerExpr && "All of these should exist in a match here.");

if (CG.size() <= 1) {
  CG.addToCallGraph(const_cast<TranslationUnitDecl *>(
      HandlerDecl->getTranslationUnitDecl()));
  assert(CG.size() > 1 &&
         "There should be at least one function added to call graph.");
}

if (!HandlerDecl->hasBody()) {
  (void)checkFunction(HandlerDecl, HandlerExpr, {});
  return;
}

CallGraphNode *HandlerNode = CG.getNode(HandlerDecl->getCanonicalDecl());
assert(HandlerNode &&
       "Handler with body should be present in the call graph.");
auto Itr = llvm::df_begin(HandlerNode), ItrE = llvm::df_end(HandlerNode);
while (Itr != ItrE) {
  const auto *CallF = dyn_cast<FunctionDecl>((*Itr)->getDecl());
  unsigned int PathL = Itr.getPathLength();
  if (CallF) {
    const Expr *CallOrRef = (PathL > 1)
                                ? findCallExpr(Itr.getPath(PathL - 2), *Itr)
                                : HandlerExpr;
    auto ChainReporter = [this, &Itr, HandlerExpr](bool SkipPathEnd) {
      reportHandlerChain(Itr, HandlerExpr, SkipPathEnd);
    };
    if (checkFunction(CallF, CallOrRef, ChainReporter))
      Itr.skipChildren();
    else
      ++Itr;
  } else {
    ++Itr;
  }
}

bool SignalHandlerCheck::isStandardFunctionAsyncSafe(const FunctionDecl *FD) const {
  assert(isStandardFunction(FD));

  const IdentifierInfo *II = FD->getIdentifier();
  if (!II)
    return false;

  if (!FD->isInStdNamespace() && !FD->isGlobal())
    return false;

  if (ConformingFunctions.count(II->getName()))
    return true;

  return false;
}

void SignalHandlerCheck::reportHandlerChain(
    const llvm::df_iterator<clang::CallGraphNode *> &Itr,
    const DeclRefExpr *HandlerRef, bool SkipPathEnd) {
  int CallLevel = Itr.getPathLength() - 2;
  assert(CallLevel >= -1 && "Empty iterator?");

  const CallGraphNode *Caller = Itr.getPath(CallLevel + 1), *Callee = nullptr;
  while (CallLevel >= 0) {
    Callee = Caller;
    Caller = Itr.getPath(CallLevel);
    const Expr *CE = findCallExpr(Caller, Callee);
    if (SkipPathEnd)
      SkipPathEnd = false;
    else
      diag(CE->getBeginLoc(), "function %0 called here from %1",
           DiagnosticIDs::Note)
          << cast<FunctionDecl>(Callee->getDecl())
          << cast<FunctionDecl>(Caller->getDecl());
    --CallLevel;
  }

  if (!SkipPathEnd)
    diag(HandlerRef->getBeginLoc(),
         "function %0 registered here as signal handler", DiagnosticIDs::Note)
        << cast<FunctionDecl>(Caller->getDecl())
        << HandlerRef->getSourceRange();
}

Expr *findCallExpr(const CallGraphNode *Caller, const CallGraphNode *Callee) {
  auto FoundCallee = llvm::find_if(
      Caller->callees(), [Callee](const CallGraphNode::CallRecord &Call) {
        return Call.Callee == Callee;
      });
  assert(FoundCallee != Caller->end() &&
         "Callee should be called from the caller function here.");
  return FoundCallee->CallExpr;
}

const auto *Definition = Result.Nodes.getNodeAs<CXXMethodDecl>("x");
if (!Definition)
  return;

if (Definition->isConst()) {
  SourceRange DefConst = getLocationOfConst(Definition->getTypeSourceInfo(),
                                            *Result.SourceManager,
                                            Result.Context->getLangOpts());
  if (DefConst.isInvalid())
