  if (DeclConst.isInvalid())
    return;
  Diag << FixItHint::CreateRemoval(DeclConst);
}

// Then remove 'const' from definition (handled in previous step or next step)

static StringRef getStringFromRange(SourceManager &SourceMgr,
                                    const LangOptions &LangOpts,
                                    SourceRange Range) {
  if (SourceMgr.getFileID(Range.getBegin()) !=
      SourceMgr.getFileID(Range.getEnd()))
    return {};

  return Lexer::getSourceText(CharSourceRange(Range, true), SourceMgr,
                              LangOpts);
}

static SourceRange getLocationOfConst(const TypeSourceInfo *TSI,
                                      SourceManager &SourceMgr,
                                      const LangOptions &LangOpts) {
  assert(TSI);
  const auto FTL = TSI->getTypeLoc().IgnoreParens().getAs<FunctionTypeLoc>();
  assert(FTL);

  SourceRange Range{FTL.getRParenLoc().getLocWithOffset(1),
                    FTL.getLocalRangeEnd()};
  StringRef Text = getStringFromRange(SourceMgr, LangOpts, Range);
  size_t Offset = Text.find("const");
  if (Offset == StringRef::npos)
    return {};

  SourceLocation Start = Range.getBegin().getLocWithOffset(Offset);
  return {Start, Start.getLocWithOffset(strlen("const") - 1)};
}

const auto *Typedef = Result.Nodes.getNodeAs<TypedefDecl>("TypeDecl");
const auto *TL = Result.Nodes.getNodeAs<TypeLoc>("TypeLoc");
if (!Typedef || !TL)
  return;

SourceLocation IoStateLoc = TL->getBeginLoc();
bool Fix = Replacement && !TL->getType()->isDependentType();
if (IoStateLoc.isMacroID()) {
  IoStateLoc = SM.getSpellingLoc(IoStateLoc);
  Fix = false;
}

if (Replacement) {
  const char *FixName = *Replacement;
  auto Builder = diag(IoStateLoc, "'std::ios_base::%0' is deprecated; use "
                                "'std::ios_base::%1' instead")
                 << TypeName << FixName;

  if (Fix)
    Builder << FixItHint::CreateReplacement(SourceRange(IoStateLoc, EndLoc),
                                            FixName);
} else
  diag(IoStateLoc, "'std::ios_base::%0' is deprecated") << TypeName;

static std::optional<const char *> getReplacementType(StringRef Type) {
  return llvm::StringSwitch<std::optional<const char *>>(Type)
      .Case("io_state", "iostate")
      .Case("open_mode", "openmode")
      .Case("seek_dir", "seekdir")
      .Default(std::nullopt);
}

auto Diag = diag(MatchedDecl->getBeginLoc(),
               formatv("prefer a lambda to {0}::bind", LP.BindNamespace).str());
if (!LP.IsFixitSupported)
  return;

std::string Buffer;
llvm::raw_string_ostream Stream(Buffer);
Stream << "[";
emitCaptureList(LP, Result, Stream);
Stream << "]";

if (LP.Callable.Type == CT_Function) {
  StringRef SourceTokens = LP.Callable.SourceTokens;
  SourceTokens.consume_front("&");
  Stream << " { return " << SourceTokens;
} else if (LP.Callable.Type == CT_MemberFunction) {
  const auto *MethodDecl = dyn_cast<CXXMethodDecl>(LP.Callable.Decl);
  const BindArgument &ObjPtr = FunctionCallArgs.front();
  Stream << " { ";
  if (!isa<CXXThisExpr>(ignoreTemporariesAndPointers(ObjPtr.E))) {
    Stream << ObjPtr.UsageIdentifier;
    Stream << "->";
  }
  Stream << MethodDecl->getName();
} else {
  Stream << " { return ";
  switch (LP.Callable.CE) {
  case CE_Var:
    if (LP.Callable.UsageIdentifier != LP.Callable.CaptureIdentifier) {
      Stream << "(" << LP.Callable.UsageIdentifier << ")";
      break;
    }
    [[fallthrough]];
  case CE_InitExpression:
    Stream << LP.Callable.UsageIdentifier;
    break;
  default:
    Stream << getSourceTextForExpr(Result, Ref);
  }
}

Stream << "(";
addFunctionCallArgs(getForwardedArgumentList(LP), Stream);
Stream << "); }";

static StringRef getSourceTextForExpr(const MatchFinder::MatchResult &Result,
                                    const Expr *E) {
  return Lexer::getSourceText(
      CharSourceRange::getTokenRange(E->getBeginLoc(), E->getEndLoc()),
      *Result.SourceManager, Result.Context->getLangOpts());
}

static bool isCallExprNamed(const Expr *E, StringRef Name) {
  const auto *CE = dyn_cast<CallExpr>(E->IgnoreImplicit());
  if (!CE)
    return false;
  const auto *ND = dyn_cast<NamedDecl>(CE->getCalleeDecl());
  if (!ND)
    return false;
  return ND->getQualifiedNameAsString() == Name;
}

for (const IncludeMarker &Marker : IncludesToBeProcessed) {
  if (Marker.Replacement.empty()) {
    diag(Marker.DiagLoc,
         "including '%0' has no effect in C++; consider removing it")
        << Marker.FileName
        << FixItHint::CreateRemoval(Marker.ReplacementRange);
  } else {
    diag(Marker.DiagLoc, "inclusion of deprecated C++ header "
                         "'%0'; consider using '%1' instead")
        << Marker.FileName << Marker.Replacement
        << FixItHint::CreateReplacement(
               Marker.ReplacementRange,
               (llvm::Twine("<") + Marker.Replacement + ">").str());
  }
}

class ExternCRefutationVisitor
    : public RecursiveASTVisitor<ExternCRefutationVisitor> {
  std::vector<IncludeMarker> &IncludesToBeProcessed;
  const SourceManager &SM;

public:
  ExternCRefutationVisitor(std::vector<IncludeMarker> &IncludesToBeProcessed,
                           SourceManager &SM)
      : IncludesToBeProcessed(IncludesToBeProcessed), SM(SM) {}
  bool shouldWalkTypesOfTypeLocs() const { return false; }
  bool shouldVisitLambdaBody() const { return false; }

  bool VisitLinkageSpecDecl(LinkageSpecDecl *LinkSpecDecl) const {
    if (LinkSpecDecl->getLanguage() != LinkageSpecDecl::lang_c ||
        !LinkSpecDecl->hasBraces())
      return true;

    auto ExternCBlockBegin = LinkSpecDecl->getBeginLoc();
    auto ExternCBlockEnd = LinkSpecDecl->getEndLoc();
    auto IsWrapped = [=, &SM = SM](const IncludeMarker &Marker) -> bool {
      return SM.isBeforeInTranslationUnit(ExternCBlockBegin, Marker.DiagLoc) &&
             SM.isBeforeInTranslationUnit(Marker.DiagLoc, ExternCBlockEnd);
    };

    llvm::erase_if(IncludesToBeProcessed, IsWrapped);
    return true;
  }
};

if (const auto *Decl = Result.Nodes.getNodeAs<DeclStmt>(IteratorDeclStmtId)) {
  replaceIterators(Decl, Result.Context);
} else if (const auto *Decl = Result.Nodes.getNodeAs<DeclStmt>(DeclWithNewId)) {
  replaceExpr(Decl, Result.Context,
              [](const Expr *Expr) { return Expr->getType(); },
              "use auto when initializing with new to avoid "
              "duplicating the type name");
} else if (const auto *Decl = Result.Nodes.getNodeAs<DeclStmt>(DeclWithCastId)) {
  replaceExpr(
      Decl, Result.Context,
      [](const Expr *Expr) {
        return cast<ExplicitCastExpr>(Expr)->getTypeAsWritten();
      },
      "use auto when initializing with a cast to avoid duplicating the type "
      "name");
} else if (const auto *Decl = Result.Nodes.getNodeAs<DeclStmt>(DeclWithTemplateCastId)) {
  replaceExpr(
      Decl, Result.Context,
      [](const Expr *Expr) {
        return cast<CallExpr>(Expr->IgnoreImplicit())
            ->getDirectCallee()
            ->getReturnType();
      },
      "use auto when initializing with a template cast to avoid duplicating "
      "the type name");
} else {
  llvm_unreachable("Bad Callback. No node provided.");
}

void UseAutoCheck::replaceIterators(const DeclStmt *D, ASTContext *Context) {
  for (const auto *Dec : D->decls()) {
    const auto *V = cast<VarDecl>(Dec);
    const Expr *ExprInit = V->getInit();

    if (const auto *E = dyn_cast<ExprWithCleanups>(ExprInit))
      ExprInit = E->getSubExpr();

    const auto *Construct = dyn_cast<CXXConstructExpr>(ExprInit);
    if (!Construct)
      continue;

    if (Construct->getNumArgs() != 1)
      return;

    const Expr *E = (*Construct->arg_begin())->IgnoreParenImpCasts();
    if (E != E->IgnoreConversionOperatorSingleStep()) {
      return;
    }

    if (const auto *NestedConstruct = dyn_cast<CXXConstructExpr>(E)) {
      if (NestedConstruct->getConstructor()->isConvertingConstructor(false))
        return;
    }
    if (!Context->hasSameType(V->getType(), E->getType()))
      return;
  }

  const auto *V = cast<VarDecl>(*D->decl_begin());
  SourceRange Range(V->getTypeSourceInfo()->getTypeLoc().getSourceRange());
  diag(Range.getBegin(), "use auto when declaring iterators")
      << FixItHint::CreateReplacement(Range, "auto");
}

void UseAutoCheck::replaceExpr(
    const DeclStmt *D, ASTContext *Context,
    llvm::function_ref<QualType(const Expr *)> GetType, StringRef Message) {
  const auto *FirstDecl = dyn_cast<VarDecl>(*D->decl_begin());
  if (!FirstDecl)
    return;

  const QualType FirstDeclType = FirstDecl->getType().getCanonicalType();

  std::vector<FixItHint> StarRemovals;
  for (const auto *Dec : D->decls()) {
    const auto *V = cast<VarDecl>(Dec);
    if (!V)
      return;

    const auto *Expr = V->getInit()->IgnoreParenImpCasts();
    if (!Expr)
      return;

    if (!Context->hasSameUnqualifiedType(V->getType(), GetType(Expr)))
      return;

    if (FirstDeclType != V->getType().getCanonicalType())
      return;

    if (RemoveStars) {
      if (Dec == *D->decl_begin())
        continue;

      auto Q = V->getTypeSourceInfo()->getTypeLoc().getAs<PointerTypeLoc>();
      while (!Q.isNull()) {
        StarRemovals.push_back(FixItHint::CreateRemoval(Q.getStarLoc()));
        Q = Q.getNextTypeLoc().getAs<PointerTypeLoc>();
      }
    }
  }

  TypeLoc Loc = FirstDecl->getTypeSourceInfo()->getTypeLoc();
  if (!RemoveStars) {
    while (Loc.getTypeLocClass() == TypeLoc::Pointer ||
           Loc.getTypeLocClass() == TypeLoc::Qualified)
      Loc = Loc.getNextTypeLoc();
  }
  while (Loc.getTypeLocClass() == TypeLoc::LValueReference ||
         Loc.getTypeLocClass() == TypeLoc::RValueReference ||
         Loc.getTypeLocClass() == TypeLoc::Qualified) {
    Loc = Loc.getNextTypeLoc();
  }
  SourceRange Range(Loc.getSourceRange());

  if (MinTypeNameLength != 0 &&
      getTypeNameLength(RemoveStars,
                        tooling::fixit::getText(Loc.getSourceRange(),
                                                FirstDecl->getASTContext())) <
          MinTypeNameLength)
    return;

  auto Diag = diag(Range.getBegin(), Message);
  Diag << FixItHint::CreateReplacement(Range, RemoveStars ? "auto " : "auto")
       << StarRemovals;
}

size_t getTypeNameLength(bool RemoveStars, StringRef Text) {
  enum CharType { Space, Alpha, Punctuation };
  CharType LastChar = Space, BeforeSpace = Punctuation;
  size_t NumChars = 0;
  int TemplateTypenameCntr = 0;
  for (const unsigned char C : Text) {
    if (C == '<')
      ++TemplateTypenameCntr;
    else if (C == '>')
      --TemplateTypenameCntr;
    const CharType NextChar =
        isAlphanumeric(C)
            ? Alpha
            : (isWhitespace(C) ||
               (!RemoveStars && TemplateTypenameCntr == 0 && C == '*'))
                  ? Space
                  : Punctuation;
    if (NextChar != Space) {
      ++NumChars;
      if (LastChar == Space && NextChar == Alpha && BeforeSpace == Alpha)
        ++NumChars;
      BeforeSpace = NextChar;
    }
    LastChar = NextChar;
  }
  return NumChars;
}

if (const auto *E = Result.Nodes.getNodeAs<Expr>(AutoPtrOwnershipTransferId)) {
  CharSourceRange Range = Lexer::makeFileCharRange(
      CharSourceRange::getTokenRange(E->getSourceRange()), SM, LangOptions());

  if (Range.isInvalid())
    return;

  auto Diag = diag(Range.getBegin(), "use std::move to transfer ownership")
              << FixItHint::CreateInsertion(Range.getBegin(), "std::move(")
              << FixItHint::CreateInsertion(Range.getEnd(), ")")
              << Inserter.createMainFileIncludeInsertion("<utility>");

  return;
}

if (const auto *TL = Result.Nodes.getNodeAs<TypeLoc>(AutoPtrTokenId)) {
  if (auto Loc = TL->getAs<TemplateSpecializationTypeLoc>())
    AutoPtrLoc = Loc.getTemplateNameLoc();
}

else if (const auto *D = Result.Nodes.getNodeAs<UsingDecl>(AutoPtrTokenId)) {
  AutoPtrLoc = D->getNameInfo().getBeginLoc();
}

if (StringRef(SM.getCharacterData(AutoPtrLoc), strlen("auto_ptr")) !=
    "auto_ptr")
  return;

SourceLocation EndLoc =
    AutoPtrLoc.getLocWithOffset(strlen("auto_ptr") - 1);
diag(AutoPtrLoc, "auto_ptr is deprecated, use unique_ptr instead")
    << FixItHint::CreateReplacement(SourceRange(AutoPtrLoc, EndLoc),
                                    "unique_ptr");

const auto *FuncClass = Result.Nodes.getNodeAs<ClassTemplateSpecializationDecl>("FunctorClass");
if (!FuncClass)
  return;

if (const auto *FuncInst = Result.Nodes.getNodeAs<CXXConstructExpr>("FuncInst")) {
  diag(FuncInst->getBeginLoc(), Message) << FuncClass->getName();
  return;
}

const auto *Functor = Result.Nodes.getNodeAs<TemplateArgument>("Functor");
const auto FunctorParentLoc = Result.Nodes.getNodeAs<TypeLoc>("FunctorParentLoc")
      ->getAs<TemplateSpecializationTypeLoc>();
if (!FunctorParentLoc)
  return;

unsigned ArgNum = 0;
const auto *FunctorParentType = FunctorParentLoc.getType()->castAs<TemplateSpecializationType>();
for (; ArgNum < FunctorParentType->template_arguments().size(); ++ArgNum) {
  const TemplateArgument &Arg = FunctorParentType->template_arguments()[ArgNum];
  if (Arg.getKind() != TemplateArgument::Type)
    continue;
  QualType ParentArgType = Arg.getAsType();
  if (ParentArgType->isRecordType() &&
      ParentArgType->getAsCXXRecordDecl() ==
          Functor->getAsType()->getAsCXXRecordDecl())
    break;
}
if (ArgNum == FunctorParentType->template_arguments().size())
  return;

TemplateArgumentLoc FunctorLoc = FunctorParentLoc.getArgLoc(ArgNum);
auto FunctorTypeLoc = getInnerTypeLocAs<TemplateSpecializationTypeLoc>(
    FunctorLoc.getTypeSourceInfo()->getTypeLoc());
if (FunctorTypeLoc.isNull())
  return;

SourceLocation ReportLoc = FunctorLoc.getLocation();
if (ReportLoc.isInvalid())
  return;
diag(ReportLoc, Message) << FuncClass->getName()
                         << FixItHint::CreateRemoval(
                                FunctorTypeLoc.getArgLoc(0).getSourceRange());

template <typename T> static T getInnerTypeLocAs(TypeLoc Loc) {
  T Result;
  while (Result.isNull() && !Loc.isNull()) {
    Result = Loc.getAs<T>();
    Loc = Loc.getNextTypeLoc();
  }
  return Result;
}

const FunctionProtoType *FnTy = nullptr;
bool DtorOrOperatorDel = false;
SourceRange Range;

if (const auto *FuncDecl = Result.Nodes.getNodeAs<FunctionDecl>("funcDecl")) {
  DtorOrOperatorDel = Result.Nodes.getNodeAs<FunctionDecl>("del-dtor");
  FnTy = FuncDecl->getType()->getAs<FunctionProtoType>();
  if (const auto *TSI = FuncDecl->getTypeSourceInfo())
    Range = TSI->getTypeLoc().castAs<FunctionTypeLoc>().getExceptionSpecRange();
} else if (const auto *ParmDecl = Result.Nodes.getNodeAs<ParmVarDecl>("parmVarDecl")) {
  FnTy = ParmDecl->getType()->castAs<Type>()->getPointeeType()->getAs<FunctionProtoType>();
  if (const auto *TSI = ParmDecl->getTypeSourceInfo())
    Range = TSI->getTypeLoc().getNextTypeLoc().IgnoreParens().castAs<FunctionProtoTypeLoc>().getExceptionSpecRange();
}

assert(FnTy && "FunctionProtoType is null.");
if (isUnresolvedExceptionSpec(FnTy->getExceptionSpecType()))
  return;

bool IsNoThrow = FnTy->isNothrow();
StringRef ReplacementStr = IsNoThrow ? NoexceptMacro.empty() ? "noexcept" : NoexceptMacro
    : NoexceptMacro.empty()
        ? (DtorOrOperatorDel || UseNoexceptFalse) ? "noexcept(false)" : ""
        : "";

FixItHint FixIt;
if ((IsNoThrow || NoexceptMacro.empty()) && CRange.isValid())
  FixIt = FixItHint::CreateReplacement(CRange, ReplacementStr);

diag(Range.getBegin(), "dynamic exception specification '%0' is deprecated; consider %select{using '%2'|removing it}1 instead")
    << Lexer::getSourceText(CRange, *Result.SourceManager, Result.Context->getLangOpts())
    << ReplacementStr.empty() << ReplacementStr << FixIt;

SourceLocation BeginLoc;
SourceLocation EndLoc;
const CallExpr *C = Result.Nodes.getNodeAs<CallExpr>("init_call_expr");
bool WarnOnly = false;

if (C) {
  BeginLoc = C->getBeginLoc();
  EndLoc = C->getEndLoc();
} else if (const auto *E = Result.Nodes.getNodeAs<CallExpr>("call_expr")) {
  BeginLoc = E->getBeginLoc();
  EndLoc = E->getEndLoc();
} else if (const auto *D =
               Result.Nodes.getNodeAs<DeclRefExpr>("decl_ref_expr")) {
  BeginLoc = D->getBeginLoc();
  EndLoc = D->getEndLoc();
  WarnOnly = true;
} else {
  const auto *U = Result.Nodes.getNodeAs<UsingDecl>("using_decl");
  assert(U && "Null pointer, no node provided");
  BeginLoc = U->getNameInfo().getBeginLoc();
  EndLoc = U->getNameInfo().getEndLoc();
}

if (!BeginLoc.isMacroID()) {
  StringRef Text =
      Lexer::getSourceText(CharSourceRange::getTokenRange(BeginLoc, EndLoc),
                           *Result.SourceManager, getLangOpts());

  Text.consume_back("()");
  int TextLength = Text.size();

  if (WarnOnly) {
    return;
  }

  if (!C) {
    Diag << FixItHint::CreateInsertion(BeginLoc.getLocWithOffset(TextLength),
                                       "s");
  } else {
    Diag << FixItHint::CreateReplacement(C->getSourceRange(),
                                         "std::uncaught_exceptions() > 0");
  }
}

const auto *PushBackCall = Result.Nodes.getNodeAs<CXXMemberCallExpr>("push_back_call");
const auto *PushCall = Result.Nodes.getNodeAs<CXXMemberCallExpr>("push_call");
const auto *PushFrontCall = Result.Nodes.getNodeAs<CXXMemberCallExpr>("push_front_call");
const auto *EmplacyCall = Result.Nodes.getNodeAs<CXXMemberCallExpr>("emplacy_call");

const CXXMemberCallExpr *Call = [&]() {
  if (PushBackCall) return PushBackCall;
  if (PushCall) return PushCall;
  if (PushFrontCall) return PushFrontCall;
  return EmplacyCall;
}();

assert(Call && "No call matched");

const auto *CtorCall = Result.Nodes.getNodeAs<CXXConstructExpr>("ctor");
const auto *MakeCall = Result.Nodes.getNodeAs<CallExpr>("make");
const auto *TemporaryExpr = Result.Nodes.getNodeAs<MaterializeTemporaryExpr>("temporary_expr");

assert((CtorCall || MakeCall) && "No push_back parameter matched");

if (IgnoreImplicitConstructors && CtorCall && CtorCall->getNumArgs() >= 1 &&
    CtorCall->getArg(0)->getSourceRange() == CtorCall->getSourceRange())
  return;

auto Diag = EmplacyCall
    ? diag(TemporaryExpr ? TemporaryExpr->getBeginLoc()
           : CtorCall    ? CtorCall->getBeginLoc()
                          : MakeCall->getBeginLoc(),
           "unnecessary temporary object created while calling %0")
    : diag(Call->getExprLoc(), "use emplace%select{|_back|_front}0 "
                             "instead of push%select{|_back|_front}0");

if (EmplacyCall)
  Diag << Call->getMethodDecl()->getName();
else if (PushCall)
  Diag << 0;
else if (PushBackCall)
  Diag << 1;
else
  Diag << 2;

if (PushBackCall) {
  const char *EmplacePrefix = MakeCall ? "emplace_back" : "emplace_back(";
  Diag << FixItHint::CreateReplacement(FunctionNameSourceRange, EmplacePrefix);
} else if (PushCall) {
  const char *EmplacePrefix = MakeCall ? "emplace" : "emplace(";
  Diag << FixItHint::CreateReplacement(FunctionNameSourceRange, EmplacePrefix);
} else if (PushFrontCall) {
  const char *EmplacePrefix = MakeCall ? "emplace_front" : "emplace_front(";
  Diag << FixItHint::CreateReplacement(FunctionNameSourceRange, EmplacePrefix);
}

const SourceRange CallParensRange =
    MakeCall ? SourceRange(MakeCall->getCallee()->getEndLoc(),
                          MakeCall->getRParenLoc())
             : CtorCall->getParenOrBraceRange();

if (CallParensRange.getBegin().isInvalid())
  return;

const SourceLocation ExprBegin = TemporaryExpr ? TemporaryExpr->getExprLoc()
                                 : CtorCall    ? CtorCall->getExprLoc()
                                               : MakeCall->getExprLoc();

const auto ParamCallSourceRange =
    CharSourceRange::getTokenRange(ExprBegin, CallParensRange.getBegin());

const auto EndCallSourceRange = CharSourceRange::getTokenRange(
    CallParensRange.getEnd(),
    TemporaryExpr ? TemporaryExpr->getEndLoc() : CallParensRange.getEnd());

Diag << FixItHint::CreateRemoval(ParamCallSourceRange)
     << FixItHint::CreateRemoval(EndCallSourceRange);

if (MakeCall && EmplacyCall) {
  Diag << FixItHint::CreateRemoval(
      CharSourceRange::getCharRange(MakeCall->getCallee()->getEndLoc(),
                                    MakeCall->getArg(0)->getBeginLoc()));
}

std::string ReplacementText;
if (const auto *UnaryOp = llvm::dyn_cast<UnaryOperator>(Container)) {
  ReplacementText = std::string(
      Lexer::getSourceText(CharSourceRange::getTokenRange(
                               UnaryOp->getSubExpr()->getSourceRange()),
                           *Result.SourceManager, Opts));
  ReplacementText += "->shrink_to_fit()";
} else {
  ReplacementText = std::string(Lexer::getSourceText(
      CharSourceRange::getTokenRange(Container->getSourceRange()),
      *Result.SourceManager, Opts));
  ReplacementText += ".shrink_to_fit()";
}

const auto *F = Result.Nodes.getNodeAs<FunctionDecl>("Func");
const auto *Fr = Result.Nodes.getNodeAs<FriendDecl>("Friend");
assert(F && "Matcher is expected to find only FunctionDecls");

const auto *AT = F->getDeclaredReturnType()->getAs<AutoType>();
if (AT != nullptr &&
    ((!AT->isConstrained() && AT->getKeyword() == AutoTypeKeyword::Auto &&
      !hasAnyNestedLocalQualifiers(F->getDeclaredReturnType())) ||
     F->isDefaulted()))
  return;

if (F->getDeclaredReturnType()->isFunctionPointerType() ||
    F->getDeclaredReturnType()->isMemberFunctionPointerType() ||
    F->getDeclaredReturnType()->isMemberPointerType()) {
  diag(F->getLocation(), Message);
  return;
}

const ASTContext &Ctx = *Result.Context;
const SourceManager &SM = *Result.SourceManager;
const LangOptions &LangOpts = getLangOpts();

const TypeSourceInfo *TSI = F->getTypeSourceInfo();
if (!TSI)
  return;

FunctionTypeLoc FTL =
    TSI->getTypeLoc().IgnoreParens().getAs<FunctionTypeLoc>();
if (!FTL) {
  diag(F->getLocation(), Message);
  return;
}

SourceLocation InsertionLoc =
    findTrailingReturnTypeSourceLocation(*F, FTL, Ctx, SM, LangOpts);
if (InsertionLoc.isInvalid()) {
  diag(F->getLocation(), Message);
  return;
}

SourceRange ReturnTypeCVRange =
    findReturnTypeAndCVSourceRange(*F, FTL.getReturnLoc(), Ctx, SM, LangOpts);
if (ReturnTypeCVRange.isInvalid())
  return;

UnqualNameVisitor UNV{*F};
UNV.TraverseTypeLoc(FTL.getReturnLoc());
if (UNV.Collision) {
  diag(F->getLocation(), Message);
  return;
}

SourceLocation ReturnTypeEnd =
    Lexer::getLocForEndOfToken(ReturnTypeCVRange.getEnd(), 0, SM, LangOpts);
StringRef CharAfterReturnType = Lexer::getSourceText(
    CharSourceRange::getCharRange(ReturnTypeEnd,
                                  ReturnTypeEnd.getLocWithOffset(1)),
    SM, LangOpts);
bool NeedSpaceAfterAuto =
    CharAfterReturnType.empty() || !llvm::isSpace(CharAfterReturnType[0]);

std::string Auto = NeedSpaceAfterAuto ? "auto " : "auto";
std::string ReturnType =
    std::string(tooling::fixit::getText(ReturnTypeCVRange, Ctx));
keepSpecifiers(ReturnType, Auto, ReturnTypeCVRange, *F, Fr, Ctx, SM,
               LangOpts);

diag(F->getLocation(), Message)
    << FixItHint::CreateReplacement(ReturnTypeCVRange, Auto)
    << FixItHint::CreateInsertion(InsertionLoc, " -> " + ReturnType);

static SourceLocation expandIfMacroId(SourceLocation Loc,
                                      const SourceManager &SM) {
  if (Loc.isMacroID())
    Loc = expandIfMacroId(SM.getImmediateExpansionRange(Loc).getBegin(), SM);
  assert(!Loc.isMacroID() &&
         "SourceLocation must not be a macro ID after recursive expansion");
  return Loc;
}

static bool hasAnyNestedLocalQualifiers(QualType Type) {
  bool Result = Type.hasLocalQualifiers();
  if (Type->isPointerType())
    Result = Result || hasAnyNestedLocalQualifiers(
                           Type->castAs<PointerType>()->getPointeeType());
  if (Type->isReferenceType())
    Result = Result || hasAnyNestedLocalQualifiers(
                           Type->castAs<ReferenceType>()->getPointeeType());
  return Result;
}

const auto *SpecialFunctionDecl = Result.Nodes.getNodeAs<CXXMethodDecl>(SpecialFunction);
if (IgnoreMacros && SpecialFunctionDecl->getLocation().isMacroID())
  return;

const auto *Body = dyn_cast<CompoundStmt>(SpecialFunctionDecl->getBody());
if (!Body)
  return;
if (!SpecialFunctionDecl->isCopyAssignmentOperator() && !Body->body_empty())
  return;

if (IgnoreMacros && utils::lexer::rangeContainsExpansionsOrDirectives(
                      Body->getSourceRange(), *Result.SourceManager,
                      Result.Context->getLangOpts()))
  return;
bool ApplyFix = SpecialFunctionDecl->isCopyAssignmentOperator() ||
               bodyEmpty(Result.Context, Body);

if (const auto *Ctor = dyn_cast<CXXConstructorDecl>(SpecialFunctionDecl)) {
  if (Ctor->getNumParams() == 0) {
    MemberType = 0;
  } else {
    if (!isCopyConstructorAndCanBeDefaulted(Result.Context, Ctor))
      return;
    MemberType = 1;
    for (const auto *Init : Ctor->inits()) {
      RemoveInitializers.emplace_back(
          FixItHint::CreateRemoval(Init->getSourceRange()));
    }
  }
}

else if (isa<CXXDestructorDecl>(SpecialFunctionDecl)) {
  MemberType = 2;
}

else {
  if (!isCopyAssignmentAndCanBeDefaulted(Result.Context, SpecialFunctionDecl))
    return;
  MemberType = 3;
}

SourceLocation Location = SpecialFunctionDecl->getLocation();
if (Location.isMacroID())
  Location = Body->getBeginLoc();
auto Diag = diag(
    Location,
    "use '= default' to define a trivial %select{default constructor|copy "
    "constructor|destructor|copy-assignment operator}0");
Diag << MemberType;
if (ApplyFix) {
  SourceLocation UnifiedEnd = utils::lexer::getUnifiedEndLoc(
      *Body, Result.Context->getSourceManager(),
      Result.Context->getLangOpts());
  std::optional<Token> Token = utils::lexer::findNextTokenSkippingComments(
      UnifiedEnd, Result.Context->getSourceManager(),
      Result.Context->getLangOpts());
  StringRef Replacement =
      Token && Token->is(tok::semi) ? "= default" : "= default;";
  Diag << FixItHint::CreateReplacement(Body->getSourceRange(), Replacement)
       << RemoveInitializers;
}

static bool bodyEmpty(const ASTContext *Context, const CompoundStmt *Body) {
  bool Invalid = false;
  StringRef Text = Lexer::getSourceText(
      CharSourceRange::getCharRange(Body->getLBracLoc().getLocWithOffset(1),
                                    Body->getRBracLoc()),
      Context->getSourceManager(), Context->getLangOpts(), &Invalid);
  return !Invalid && std::strspn(Text.data(), " \t\r\n") == Text.size();
}

static std::set<const FieldDecl *>
getAllNamedFields(const CXXRecordDecl *Record) {
  std::set<const FieldDecl *> Result;
  for (const auto *Field : Record->fields()) {
    if (Field->isUnnamedBitfield())
      continue;
    Result.insert(Field);
  }
  return Result;
}

static std::set<const Type *> getAllDirectBases(const CXXRecordDecl *Record) {
  std::set<const Type *> Result;
  for (auto Base : Record->bases()) {
    const auto *BaseType = Base.getTypeSourceInfo()->getType().getTypePtr();
    Result.insert(BaseType);
  }
  return Result;
}

const auto *MatchedDecl = Result.Nodes.getNodeAs<CXXMethodDecl>("no_discard");
