static bool doesNoDiscardMacroExist(ASTContext &Context,
                                    const llvm::StringRef &MacroId) {
  if (MacroId.startswith("[[") || MacroId.startswith("__attribute__"))
    return true;
  return Context.Idents.get(MacroId).hasMacroDefinition();
}

